// === RENDERERS: DETAIL SCREEN ===
function renderLeadDetail() {
  if (!currentLead) return;

  let html = `
    <!-- Meta Strip -->
    <div class="meta-strip" id="detail-meta"></div>
    <!-- Stage Bar -->
    <div class="stage-bar" id="detail-stagebar"></div>
    <!-- Body 3 Columns -->
    <div class="detail-body">
      <div class="zone-left" id="detail-left"></div>
      <div class="zone-center" id="detail-center"></div>
      <div class="zone-right" id="detail-right"></div>
    </div>
  `;
  document.getElementById('screen-detail').innerHTML = html;

  renderMetaStrip();
  renderStageBar();
  renderLeftSidebar();
  renderCenterPanel();
  renderRightPanel();
}

function renderMetaStrip() {
  const l = currentLead;
  let html = `
    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px;">
      <div style="display:flex; align-items:center; gap:12px;">
        <div style="width:36px; height:36px; border-radius:50%; background:linear-gradient(135deg, var(--primary), #9F7AEA); color:white; display:flex; align-items:center; justify-content:center; font-weight:700; font-size:14px;">${l.name.charAt(0)}</div>
        <div style="font-size:16px; font-weight:700;">${l.name}</div>
        <span class="badge badge-${l.product}">${getProductLabel(l.product)}</span>
        <span class="badge badge-${l.source}">${l.source.toUpperCase()}</span>
      </div>
      <div style="display:flex; gap:12px;">
        <button class="btn btn-ghost" onclick="closeLead()">← Back to List</button>
        <button class="btn btn-primary" onclick="showToast('Primary action triggered')">Next Action</button>
        <button class="btn btn-danger">Mark as Lost</button>
      </div>
    </div>
    <div style="display:flex; gap:20px;">
      <div style="flex:1; border-right:1px solid var(--border); padding-right:20px;">
        <div class="label">Lead Identity</div>
        <div style="font-weight:600;">${l.id}</div>
        <div style="color:var(--text-muted); font-size:12px;">Created: ${l.createdDate}</div>
      </div>
      <div style="flex:1; border-right:1px solid var(--border); padding-right:20px;">
        <div class="label">Product Info</div>
        <div style="font-weight:600;">${getProductLabel(l.product)}</div>
        <div style="color:var(--text-muted); font-size:12px;">Plan: ${l.subProduct}</div>
      </div>
      <div style="flex:1; border-right:1px solid var(--border); padding-right:20px;">
        <div class="label">Status</div>
        <div style="font-weight:600; color:var(--primary);">${getStageLabel(l.stage)}</div>
        <div style="color:var(--text-muted); font-size:12px;">${l.subStatus}</div>
      </div>
      <div style="flex:1; display:flex; justify-content:space-between; align-items:center;">
        <div>
          <div class="label">HL Context</div>
          <div style="font-weight:600;">${l.hlLead ? getStageLabel(l.hlLead.hlStage) : 'No HL Linked'}</div>
          <div style="color:var(--text-muted); font-size:12px;">${l.hlLead ? l.hlLead.id + ' • ' + formatLakhs(l.hlLead.si) : '-'}</div>
        </div>
        <div style="display:flex; gap:8px;">
          <div style="width:32px; height:32px; border-radius:50%; background:#22C55E; color:white; display:flex; align-items:center; justify-content:center; cursor:pointer;" onclick="showToast('WhatsApp opened')">W</div>
          <div style="width:32px; height:32px; border-radius:50%; background:#3B82F6; color:white; display:flex; align-items:center; justify-content:center; cursor:pointer;" onclick="showToast('Email opened')">@</div>
          <div style="width:32px; height:32px; border-radius:50%; background:#F97316; color:white; display:flex; align-items:center; justify-content:center; cursor:pointer;" onclick="showToast('Call opened')">📞</div>
        </div>
      </div>
    </div>
  `;
  document.getElementById('detail-meta').innerHTML = html;
}

function renderStageBar() {
  const idx = STAGES.indexOf(currentLead.stage);
  let html = '<div style="display:flex; align-items:center; width:100%; max-width:800px; margin:0 auto; position:relative;">';

  STAGES.forEach((st, i) => {
    let isDone = i < idx;
    let isCurrent = i === idx;
    let bg = isDone ? 'var(--primary)' : 'var(--white)';
    let border = isCurrent ? '2px solid var(--primary)' : (isDone ? '2px solid var(--primary)' : '2px solid var(--border)');
    let color = isDone ? 'white' : (isCurrent ? 'var(--primary)' : 'var(--text-muted)');
    let content = isDone ? '✓' : (i + 1);
    let fontWeight = isCurrent ? '700' : '500';

    html += `
      <div style="display:flex; flex-direction:column; align-items:center; flex:1; position:relative; z-index:2; cursor:pointer;" onclick="gMoveStage('${st}')">
        <div style="width:28px; height:28px; border-radius:50%; background:${bg}; border:${border}; color:${color}; display:flex; align-items:center; justify-content:center; font-size:12px; font-weight:bold; margin-bottom:6px;">${content}</div>
        <div style="font-size:10px; font-weight:${fontWeight}; color:${isCurrent||isDone ? 'var(--primary)' : 'var(--text-muted)'}; text-transform:uppercase; letter-spacing:0.5px;">${getStageLabel(st)}</div>
      </div>
    `;
    if (i < STAGES.length - 1) {
      let lineBg = i < idx ? 'var(--primary)' : 'var(--border)';
      html += `<div style="position:absolute; top:14px; left:calc(${(i * 100/STAGES.length) + (100/(STAGES.length*2))}%); width:calc(${100/STAGES.length}%); height:2px; background:${lineBg}; z-index:1;"></div>`;
    }
  });
  html += '</div>';
  document.getElementById('detail-stagebar').innerHTML = html;
}

function gMoveStage(newStage) {
  currentLead.stage = newStage;
  currentLead.log.unshift({ dot: 'var(--primary)', text: 'Stage changed to ' + getStageLabel(newStage), time: 'Just now' });
  renderStageBar();
  renderCenterPanel();
  renderRightPanel();
  showToast('Stage moved to ' + getStageLabel(newStage));
}

function renderLeftSidebar() {
  document.getElementById('detail-left').innerHTML = `<div>Left Sidebar (Coming Soon)</div>`;
}

function renderCenterPanel() {
  document.getElementById('detail-center').innerHTML = `<div>Center Panel - Stage: ${getStageLabel(currentLead.stage)} (Coming Soon)</div>`;
}

function renderRightPanel() {
  document.getElementById('detail-right').innerHTML = `<div>Right Panel (Coming Soon)</div>`;
}

