function renderLeftSidebar() {
  const sections = ['Customer Details', 'Income Details', 'Property Details', 'Insurance Details', 'Nominee Details', 'Health Screening'];
  let html = `<div style="font-weight:700; margin-bottom:12px;">Application Data</div>`;

  sections.forEach(sec => {
    let isActive = G_SECTION === sec;
    html += `
      <div class="nav-section ${isActive ? 'active' : ''}" onclick="setSection('${sec}')">
        <div class="nav-dot"></div>
        <div>${sec}</div>
      </div>
    `;
  });

  // Premium Status
  let stIdx = STAGES.indexOf(currentLead.stage);
  let pShared = stIdx >= STAGES.indexOf('quote') && currentLead.subStatus !== 'New Lead';
  let pPaid = stIdx >= STAGES.indexOf('processing');
  let pIssued = stIdx >= STAGES.indexOf('policy');

  html += `
    <div style="margin-top:24px; margin-bottom:12px; font-weight:700;">Premium Status</div>
    <div style="display:flex; flex-direction:column; gap:8px; font-size:12px;">
      <div style="display:flex; align-items:center; gap:8px;">
        <div style="width:12px; height:12px; border-radius:50%; border:2px solid var(--primary); background:${pShared ? 'var(--primary)' : 'transparent'};"></div>
        <span>Quote Shared</span>
      </div>
      <div style="display:flex; align-items:center; gap:8px;">
        <div style="width:12px; height:12px; border-radius:50%; border:2px solid var(--primary); background:${pPaid ? 'var(--primary)' : 'transparent'};"></div>
        <span>Payment Received</span>
      </div>
      <div style="display:flex; align-items:center; gap:8px;">
        <div style="width:12px; height:12px; border-radius:50%; border:2px solid var(--primary); background:${pIssued ? 'var(--primary)' : 'transparent'};"></div>
        <span>Policy Issued</span>
      </div>
    </div>
  `;

  // Linked Home Loan
  const hl = currentLead.hlLead;
  if (hl) {
    html += `
      <div class="hl-card">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">
          <div style="font-weight:600;">🏠 Linked Home Loan</div>
          <span class="badge badge-property" style="background:#E5E7EB; color:#374151;">${hl.id}</span>
        </div>
        <div style="font-size:12px; color:var(--text-muted); margin-bottom:4px;">Stage: <span style="font-weight:600; color:var(--primary);">${getStageLabel(hl.hlStage)}</span></div>
        <div style="font-size:12px; color:var(--text-muted); margin-bottom:4px;">Bank: <span style="font-weight:600; color:var(--text-body);">${hl.bank}</span></div>
        <div style="font-size:12px; color:var(--text-muted); margin-bottom:8px;">Loan Amount: <span style="font-weight:600; color:var(--text-body);">${formatLakhs(hl.si)}</span></div>
        <button class="btn btn-ghost" style="width:100%; font-size:11px; padding:4px;" onclick="showToast('Opening HL Lead in Sangam...')">Open in Sangam →</button>
      </div>
    `;
  } else {
    html += `
      <div class="hl-card" style="text-align:center;">
        <div style="font-size:12px; color:var(--text-muted); margin-bottom:8px;">No home loan lead linked</div>
        <button class="btn btn-ghost btn-small" onclick="showToast('Search modal opening...')">+ Link HL Lead</button>
      </div>
    `;
  }

  document.getElementById('detail-left').innerHTML = html;
}

function setSection(sec) {
  G_SECTION = sec;
  renderLeftSidebar();
  renderCenterPanel();
}

