function setSection(sec) {
  G_SECTION = sec;
  renderLeftSidebar();
  renderCenterPanel();
}

function renderCenterPanel() {
  const el = document.getElementById('detail-center');
  if (G_SECTION) {
    el.innerHTML = renderSectionForm(G_SECTION);
    return;
  }

  switch (currentLead.stage) {
    case 'outreach': el.innerHTML = renderOutreachStage(); break;
    case 'interest': el.innerHTML = renderInterestStage(); break;
    case 'quote': el.innerHTML = renderQuoteStage(); break;
    case 'payment': el.innerHTML = renderPaymentStage(); break;
    case 'processing': el.innerHTML = renderProcessingStage(); break;
    case 'policy': el.innerHTML = renderPolicyStage(); break;
    default: el.innerHTML = `<div>Stage: ${getStageLabel(currentLead.stage)} content coming soon</div>`;
  }
}

function renderOutreachStage() {
  return `
    <div class="call-card">
      <div class="label" style="color:var(--primary); margin-bottom:12px;">📞 Next Action — Call the customer</div>
      <div style="font-size:18px; font-weight:600; margin-bottom:4px;">${currentLead.name}</div>
      <div style="font-size:26px; font-weight:800; color:var(--text-heading); margin-bottom:24px;">
        ${currentLead.phone}
        <button class="btn btn-ghost btn-small" style="margin-left:8px;" onclick="showToast('Number copied')">Copy</button>
      </div>
      <div style="display:flex; justify-content:center; gap:16px;">
        <button class="btn btn-primary" onclick="gCallOut('connected')">✓ Connected</button>
        <button class="btn btn-danger" onclick="gCallOut('not_connected')">✗ Not Connected</button>
        <button class="btn btn-ghost" onclick="gCallOut('callback')">⏰ Callback</button>
      </div>
    </div>
  `;
}

function gCallOut(result) {
  if(result === 'connected') {
    currentLead.subStatus = 'Connected';
    gMoveStage('interest');
  } else {
    currentLead.subStatus = result === 'not_connected' ? 'Not Connected' : 'Callback Scheduled';
    currentLead.log.unshift({ dot: 'var(--danger)', text: 'Call outcome: ' + currentLead.subStatus, time: 'Just now' });
    renderCenterPanel();
    renderRightPanel();
    showToast('Call logged');
  }
}

function renderInterestStage() {
  let desc = '';
  if(currentLead.product === 'lp') desc = 'Loan protection covers the home loan EMI in case of critical illness or accidents.';
  else if(currentLead.product === 'property') desc = 'Property insurance protects the physical structure of the home.';
  else if(currentLead.product === 'cl') desc = 'Credit life insurance pays off the outstanding loan balance in case of death.';
  else if(currentLead.product === 'term') desc = 'Term plan offers comprehensive life cover for the family.';

  return `
    <div class="stage-card">
      <div class="badge badge-${currentLead.product}" style="margin-bottom:12px;">Customer is Interested</div>
      <h2 style="margin-bottom:8px;">Ready to generate the quote</h2>
      <p style="color:var(--text-muted); margin-bottom:24px;">${desc}</p>
      <div style="display:flex; gap:12px;">
        <button class="btn btn-primary" onclick="gMoveStage('quote')">✦ Generate Quote</button>
        <button class="btn btn-ghost">Schedule Callback</button>
      </div>
    </div>
  `;
}

