          <div style="font-size:11px; color:var(--text-muted);">${m.date}</div>
        </div>
      `;
    } else if (cls === 'active') {
      let docsHtml = '';
      if (m.docs) {
        docsHtml = `<div style="margin-top:12px; border-top:1px solid var(--border); padding-top:12px;">`;
        m.docs.forEach((d, didx) => {
          let dkey = `${currentLead.id}_${idx}_${didx}`;
          let stat = G_DS[dkey] || 'pending';
          let isDocDone = stat === 'received';
          docsHtml += `
            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px; padding:6px 8px; border-radius:4px; background:${isDocDone?'#DCFCE7':'#F3F4F6'};">
              <div style="font-size:12px; display:flex; align-items:center; gap:6px;">
                ${isDocDone ? `<span style="color:var(--success);">✓</span>` : '📄'} ${d}
              </div>
              <select class="form-control" style="width:auto; padding:2px 4px; font-size:11px;" onchange="updateDoc('${dkey}', this.value)">
                <option value="pending" ${stat==='pending'?'selected':''}>Pending</option>
                <option value="partial" ${stat==='partial'?'selected':''}>Partial</option>
                <option value="received" ${stat==='received'?'selected':''}>Received</option>
              </select>
            </div>
          `;
        });
        docsHtml += `</div>`;
      }

      let appHtml = '';
      if (m.hasApproval) {
        let akey = `${currentLead.id}_${idx}`;
        let ares = G_AP[akey] || null;
        appHtml = `
          <div style="margin-top:12px; display:flex; gap:8px;">
            <button class="btn btn-small ${ares==='appr'?'btn-primary':'btn-ghost'}" style="${ares==='appr'?'background:var(--success);border-color:var(--success);':''}" onclick="setApproval('${akey}', 'appr')">✓ Approved</button>
            <button class="btn btn-small ${ares==='count'?'btn-primary':'btn-ghost'}" style="${ares==='count'?'background:var(--warning);border-color:var(--warning);':''}" onclick="setApproval('${akey}', 'count')">⇆ Counter</button>
            <button class="btn btn-small ${ares==='rej'?'btn-danger':'btn-ghost'}" style="${ares==='rej'?'background:var(--danger);color:white;border-color:var(--danger);':''}" onclick="setApproval('${akey}', 'rej')">✗ Rejected</button>
          </div>
          ${ares==='count' ? `<div style="color:var(--warning); font-size:11px; margin-top:8px;">Counter offer received. Needs customer consent.</div>` : ''}
          ${ares==='rej' ? `<div style="color:var(--danger); font-size:11px; margin-top:8px;">Application rejected.</div>` : ''}
        `;
      }

      content = `
        <div style="font-weight:700; color:var(--primary); margin-bottom:4px;">${m.label}</div>
        <div style="font-size:12px; color:var(--text-muted);">${m.desc}</div>
        ${docsHtml}
        ${appHtml}
        <div style="margin-top:16px;">
          <button class="btn btn-primary" onclick="markMilestoneDone(${idx})">Mark Complete →</button>
        </div>
      `;
    } else {
      content = `
        <div style="display:flex; justify-content:space-between; align-items:center;">
          <div style="font-weight:500; color:var(--text-muted);">${m.label}</div>
          <div style="font-size:11px; color:var(--text-placeholder);">Waiting</div>
        </div>
      `;
    }

    html += `
      <div class="ms-item ${cls}">
        <div class="ms-dot"></div>
        <div class="ms-card">${content}</div>
      </div>
    `;
  });

  html += `
      </div>
    </div>
  `;
  return html;
}

function updateDoc(k, v) { G_DS[k] = v; renderCenterPanel(); }
function setApproval(k, v) { G_AP[k] = v; renderCenterPanel(); }

function markMilestoneDone(idx) {
  let list = G_MS[currentLead.id];
  list[idx].status = 'done';
  list[idx].date = 'Today';
  currentLead.log.unshift({ dot: 'var(--primary)', text: 'Milestone completed: ' + list[idx].label, time: 'Just now' });

  if (idx + 1 < list.length) {
    list[idx+1].status = 'active';
  }

  // Check if policy issued milestone is done
  let polIdx = list.findIndex(m => m.id === 'pol');
  if (polIdx !== -1 && list[polIdx].status === 'done' && currentLead.stage !== 'policy') {
    gMoveStage('policy');
    return; // stage change re-renders
  }

  renderCenterPanel();
  renderRightPanel();
  showToast('Milestone completed');
}

