args.ReplacementContent:
function gCallOut(result, reason='') {
  if(result === 'connected') {
    currentLead.subStatus = 'Connected';
    gMoveStage('interest');
  } else {
    currentLead.subStatus = result === 'not_connected' ? 'Not Connected' : 'Callback Scheduled';
    let text = result === 'not_connected' ? `Call outcome: Not Connected (${reason})` : `Call outcome: Callback Scheduled`;
    currentLead.log.unshift({ dot: 'var(--danger)', text: text, time: 'Just now' });
    renderCenterPanel();
    renderRightPanel();
    showToast('Call logged');
  }
}

