function renderStageBar() {
  const idx = STAGES.indexOf(currentLead.stage);
  let html = '<div class="sangam-tracker-box"><div class="tracker-row">';

  STAGES.forEach((st, i) => {
    let isDone = i < idx;
    let isCurrent = i === idx;
    let classes = 'tracker-step';
    if(isDone) classes += ' done';
    if(isCurrent) classes += ' active';

    let content = getStageLabel(st);

    html += `
      <div class="${classes}" style="cursor:pointer;" onclick="gMoveStage('${st}')">
        ${content}
      </div>
    `;
  });
  html += '</div></div>';
  return html;
}

ReplacementChunks.TargetContent:
function renderStageBar() {
  const idx = STAGES.indexOf(currentLead.stage);
  let html = '<div style="display:flex; align-items:center; width:100%; max-width:900px; margin:0 auto; position:relative; padding: 24px 0;">';

  STAGES.forEach((st, i) => {
    let isDone = i < idx;
    let isCurrent = i === idx;
    let bg = isDone ? 'var(--success)' : (isCurrent ? 'var(--primary)' : 'var(--bg)');
    let border = isDone ? '2px solid var(--success)' : (isCurrent ? '4px solid #E0E7FF' : '2px solid var(--border)');
    let color = (isDone || isCurrent) ? 'white' : 'var(--text-placeholder)';
    let content = isDone ? '✓' : (i + 1);
    let fontWeight = isCurrent ? '700' : '500';
    let textCol = isDone ? 'var(--success)' : (isCurrent ? 'var(--primary)' : 'var(--text-placeholder)');

    html += `
      <div style="display:flex; flex-direction:column; align-items:center; flex:1; position:relative; z-index:2; cursor:pointer;" onclick="gMoveStage('${st}')">
        <div style="width:36px; height:36px; border-radius:50%; background:${bg}; box-shadow:${isCurrent?'0 0 0 4px var(--primary-light)':'none'}; border:${border}; color:${color}; display:flex; align-items:center; justify-content:center; font-size:14px; font-weight:bold; margin-bottom:8px; transition:all 0.2s;">${content}</div>
        <div style="font-size:11px; font-weight:${fontWeight}; color:${textCol}; text-transform:uppercase; letter-spacing:0.5px; text-align:center;">${getStageLabel(st)}</div>
      </div>
    `;
    if (i < STAGES.length - 1) {
      let lineBg = i < idx ? 'var(--success)' : 'var(--border)';
      html += `<div style="position:absolute; top:42px; left:calc(${(i * 100/STAGES.length) + (100/(STAGES.length*2))}%); width:calc(${100/STAGES.length}%); height:3px; background:${lineBg}; z-index:1;"></div>`;
    }
  });
  html += '</div>';
  document.getElementById('detail-stagebar').innerHTML = html;
}

