    let runningDays = 0;
    G_MS[leadId] = tpl.map((m, i) => {
      let stat = i === 0 ? 'done' : (i === 1 ? 'active' : 'pending');
      // For active state, we inject some actual TAT logic
      let actualDays = stat === 'done' ? m.tat : (stat === 'active' ? (m.tat + 2) : 0); // Active is +2 days SLA breach for demo
