function renderProcessingStage() {
  initMilestones(currentLead.id);
  const msList = G_MS[currentLead.id];
  const doneCount = msList.filter(m => m.status === 'done').length;
  const pct = Math.round((doneCount / msList.length) * 100);

  let html = `
    <div class="stage-card">
      <div style="display:flex; justify-content:space-between; align-items:end; margin-bottom:12px;">
