      </div>
      <div class="progress-track"><div class="progress-fill" style="width:${pct}%;"></div></div>

      <div class="ms-timeline">
  `;

  msList.forEach((m, idx) => {
    let cls = m.status;
    let content = '';

    if (cls === 'done') {
      content = `
        <div style="display:flex; justify-content:space-between; align-items:center;">
