          <div style="font-size:11px; color:var(--text-muted);">${m.date}</div>
        </div>
      `;
    } else if (cls === 'active') {
      let dueBadge = '';
      if (m.actual > m.tat) {
        dueBadge = `<div class="badge" style="background:#FEF2F2; color:#EF4444; font-weight:600; font-size:10px; border:1px solid #FCA5A5;">⚠ SLA Breached (${m.actual} Days)</div>`;
      } else {
        dueBadge = `<div class="badge" style="background:#F3F4F6; color:var(--text-muted); font-weight:600; font-size:10px;">Expected: ${m.tat} Days</div>`;
      }

      let actionHtml = '';
      if (m.type === 'kyc' || m.type === 'docs') {
        let docsHtml = `<div style="margin-top:12px; border-top:1px solid var(--border); padding-top:12px;">`;
        let allDone = true;
        m.docs.forEach((d, didx) => {
          let dkey = `${currentLead.id}_${idx}_${didx}`;
