function renderStageBar() {
  const idx = BUCKETS.indexOf(currentLead.bucket);
  let html = '<div class="sangam-tracker-box"><div class="tracker-row">';

  BUCKETS.forEach((st, i) => {
    let isDone = i < idx;
    let isCurrent = i === idx;
    let isLost = currentLead.bucket === 'Lost';

    let classes = 'tracker-step';
    if(isDone && !isLost) classes += ' done';
    if(isCurrent) {
       classes += ' active';
       if(isLost) classes += ' lost-active'; // Optional: add special styling for Lost
    }

    let content = st;

    html += `
      <div class="${classes}" style="cursor:default;">
        ${content}
      </div>
    `;
  });
  html += '</div></div>';
  return html;
}

function transitionLeadState(newStatus, newSubStatus, remarks, followUpDate, pendingWith) {
  const l = currentLead;
  const oldBucket = l.bucket;
  const oldStatus = l.status;

  l.status = newStatus;
  l.subStatus = newSubStatus;

  // Auto Bucket Transitions
  if (oldBucket === 'New') {
    if (newStatus === 'Connected') l.bucket = 'Contacted';
    if (newStatus === 'Not Connected') {
      l.attempts = (l.attempts || 0) + 1;
      if (l.attempts >= 3) {
        l.bucket = 'Lost';
        l.status = 'Contact Failed';
        l.subStatus = 'No Response After 3 Attempts';
      }
    }
  } else if (oldBucket === 'Contacted') {
    if (newStatus === 'Interested') l.bucket = 'Quote';
    if (newStatus === 'Not Interested') l.bucket = 'Lost';
  } else if (oldBucket === 'Processing') {
    if (newStatus === 'Insurer Rejected' || newStatus === 'Counter Offer Rejected') l.bucket = 'Lost';
    // Note: Moving to Policy is handled by MS tracker completion
  } else if (oldBucket === 'Policy') {
    if (newStatus === 'Policy Cancelled') l.bucket = 'Lost';
  }

  if (oldBucket !== l.bucket) {
    l.log.unshift({ dot: 'var(--primary)', text: `Bucket changed to ${l.bucket}`, time: 'Just now' });
  }
  l.log.unshift({ dot: '#10B981', text: `Status updated to ${l.status} - ${l.subStatus}`, time: 'Just now' });

  showToast('Lead state updated successfully');
  renderLeadDetail(); // Re-render everything to apply new state
}

