  `;
  document.body.appendChild(overlay);

  currentLead.log.unshift({ dot: '#16A34A', text: `Plan selected: ${PB_PLANS[G_PBI].insurer} · ₹${PB_PLANS[G_PBI].total} · Payment link generated`, time: 'Just now' });
  let subStatus = currentLead.finalProduct === 'lp' ? currentLead.finalInsurer : getProductLabel(currentLead.finalProduct);
  transitionLeadState('Quote Shared', 'Payment Link shared', '', '', '');
}

function handleShare(method) {
  const modal = document.getElementById('shareLinkModal');
  if (modal) document.body.removeChild(modal);

  if (method !== 'None') {
    currentLead.log.unshift({ dot: 'var(--primary)', text: `Payment link shared via ${method}`, time: 'Just now' });
    showToast(`Payment link shared via ${method} ✓`);
    renderLeadDetail();
  } else {
    showToast('Payment link copied to clipboard.');
  }
}

