function saveStatusUpdate() {
  const newStatus = document.getElementById('update-status').value;
  const newSubStatus = document.getElementById('update-substatus').value;
  const followUpDate = document.getElementById('update-followup').value;
  const pendingWith = document.getElementById('update-pending').value;
  const remarks = document.getElementById('update-remarks').value;

  const reqFollowUp = ['Call Back', 'Consent Pending', 'Payment Pending', 'Documents Pending'];
