     currentLead.finalProduct = G_PRODUCT_TAB || 'lp';
     currentLead.finalInsurer = currentLead.selectedPlan ? currentLead.selectedPlan.insurer : 'CARE Health Insurance';
  }

  transitionLeadState(newStatus, newSubStatus, remarks, followUpDate, pendingWith);
}

