window.handleStatusChange = function(status) {
  document.getElementById('update-substatus').innerHTML = (SUBSTATUS_MAP[status] || []).map(s => `<option value="${s}">${s}</option>`).join('');

  let html = '';
  if (status === 'Not Connected' || status === 'Callback') {
    html = `
      <div style="display:grid; grid-template-columns:1fr 1fr; gap:12px;">
        <div>
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Follow-up Date *</label>
          <input type="date" class="form-control" style="padding:6px; font-size:12px;" id="update-fdate">
        </div>
        <div>
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Follow-up Time *</label>
          <input type="time" class="form-control" style="padding:6px; font-size:12px;" id="update-ftime">
        </div>
      </div>
    `;
  } else if (status === 'Payment Done') {
    html = `
      <div>
        <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Payment Proof Upload *</label>
        <input type="file" class="form-control" style="padding:6px; font-size:12px;" id="update-proof">
      </div>
      <div>
        <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Enter UTR *</label>
        <input type="text" class="form-control" style="padding:6px; font-size:12px;" placeholder="e.g. UTR12345678" id="update-utr">
      </div>
    `;
  } else if (status === 'Policy Issued') {
    html = `
      <div>
        <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Policy Copy Upload *</label>
        <input type="file" class="form-control" style="padding:6px; font-size:12px;" id="update-policy">
      </div>
    `;
  }

  html += `
    <div>
      <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Remarks ${status==='Counter Offer' ? '*' : ''}</label>
      <textarea class="form-control" rows="2" style="padding:6px; font-size:12px;" id="update-remarks"></textarea>
    </div>
  `;

  const df = document.getElementById('dynamic-fields');
  if(df) df.innerHTML = html;
};

function renderRightPanel() {
  const l = currentLead;
  let nextAction = '';
  let blocker = '';

  if(l.bucket === 'New') {
    nextAction = 'Call Customer to pitch ' + getProductLabel(l.finalProduct || l.initialProduct);
    blocker = 'None';
  } else if(l.bucket === 'Contacted') {
    nextAction = 'Generate & Share Quote';
    blocker = 'Customer needs time to decide';
  } else if(l.bucket === 'Quote') {
    nextAction = 'Share Quote via WhatsApp';
    blocker = 'Awaiting customer confirmation';
  } else if(l.bucket === 'Processing') {
    initMilestones(l.id);
    const msList = G_MS[l.id];
    const activeMs = msList ? msList.find(m => m.status === 'active') : null;
    if (activeMs) {
       nextAction = 'Complete ' + activeMs.label;
       blocker = `Waiting for ${activeMs.owner || 'IBM Agent'} (Age: ${activeMs.actual || 0} days)`;
    } else {
       nextAction = 'Review Milestones';
       blocker = 'None';
    }
  } else if(l.bucket === 'Policy') {
    nextAction = 'Share Policy Document';
    blocker = 'Waiting for MIS Submission';
  } else {
    nextAction = 'Review Lead';
    blocker = 'None';
  }

  let currentStatusOptions = STATUS_MAP[l.bucket] || [];
  if (l.status && !currentStatusOptions.includes(l.status)) {
     currentStatusOptions = [l.status, ...currentStatusOptions];
  }
  let statusOptions = currentStatusOptions.map(s => `<option value="${s}" ${s === l.status ? 'selected' : ''}>${s}</option>`).join('');

  let currentSubOptions = SUBSTATUS_MAP[l.status] || [];
  if (l.subStatus && !currentSubOptions.includes(l.subStatus)) {
     currentSubOptions = [l.subStatus, ...currentSubOptions];
  }
  let subStatusOptions = currentSubOptions.map(s => `<option value="${s}" ${s === l.subStatus ? 'selected' : ''}>${s}</option>`).join('');

  let html = `
    <div class="card" style="padding: 24px 16px; border:none; box-shadow:0 4px 15px rgba(0,0,0,0.05); background:var(--white); border-radius:12px;">
      <div style="font-weight:700; margin-bottom:16px;">Update Status</div>
      <div style="display:flex; flex-direction:column; gap:12px; margin-bottom:16px;">
        <div>
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Status</label>
          <select class="form-control" style="padding:6px; font-size:12px;" id="update-status" onchange="handleStatusChange(this.value)">
            ${statusOptions}
          </select>
        </div>
        <div>
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Sub Status</label>
          <select class="form-control" style="padding:6px; font-size:12px;" id="update-substatus">
            ${subStatusOptions}
          </select>
        </div>
        <div id="dynamic-fields" style="display:flex; flex-direction:column; gap:12px;">
          <!-- Populated dynamically -->
        </div>
      </div>
      <button class="btn btn-primary" style="width:100%; border-radius:8px;" onclick="saveStatusUpdate()">Update Status</button>
    </div>
  `;
  document.getElementById('detail-right').innerHTML = html;

  // Initialize dynamic fields based on current selected status
  const initialStatus = document.getElementById('update-status').value;
  handleStatusChange(initialStatus);

  // Restore previously saved sub-status
  document.getElementById('update-substatus').value = l.subStatus;
}

function saveStatusUpdate() {
  const newStatus = document.getElementById('update-status').value;
  const newSubStatus = document.getElementById('update-substatus').value;

  // Dynamic fields extraction
  const remarksEl = document.getElementById('update-remarks');
  const remarks = remarksEl ? remarksEl.value : '';

  let followUpDate = '', followUpTime = '';
  if (newStatus === 'Not Connected' || newStatus === 'Callback') {
    followUpDate = document.getElementById('update-fdate').value;
    followUpTime = document.getElementById('update-ftime').value;
    if (!followUpDate || !followUpTime) {
      showToast('Follow-up Date and Time are mandatory', false);
      return;
    }
  }

  if (newStatus === 'Payment Done' && newSubStatus === 'Payment Verified') {
    const proof = document.getElementById('update-proof').value;
    const utr = document.getElementById('update-utr').value;
    if (!proof || !utr) {
      showToast('Payment proof upload and UTR are mandatory', false);
      return;
    }
  }

  if (newStatus === 'Policy Issued') {
    const doc = document.getElementById('update-policy').value;
    if (!doc) {
      showToast('Policy document upload is mandatory', false);
      return;
    }
  }

  if (newStatus === 'Counter Offer' && newSubStatus === 'Accepted' && !remarks.trim()) {
    showToast('Remarks are mandatory when accepting a counter offer', false);
    return;
  }

  if (newStatus === 'Payment Done' && newSubStatus === 'Payment Verified' && currentLead.bucket === 'Quote') {
     currentLead.paymentVerified = true;
     currentLead.productStatus = 'locked';
     currentLead.finalProduct = G_PRODUCT_TAB || 'lp';
     currentLead.finalInsurer = currentLead.selectedPlan ? currentLead.selectedPlan.insurer : 'CARE Health Insurance';
  }

  transitionLeadState(newStatus, newSubStatus, remarks, followUpDate, '');

  // Task Engine logic
  if (newStatus === 'Not Connected' || newStatus === 'Callback') {
    if (!window.G_TASKS) window.G_TASKS = [];
    window.G_TASKS.push({
      id: 'task_' + Date.now(),
      leadId: currentLead.id,
      leadName: currentLead.name,
      taskType: newStatus,
      date: followUpDate,
      time: followUpTime,
      status: 'pending'
    });
    showToast('Follow-up Task Created Automatically');
  }
}

