    if (activeMs) {
       nextAction = 'Complete ' + activeMs.label;
       blocker = `Waiting for ${activeMs.owner} (Age: ${activeMs.actual || 0} days)`;
    } else {
       nextAction = 'Review Milestones';
       blocker = 'None';
    }
  } else if(l.bucket === 'Policy') {
    nextAction = 'Share Policy Document';
    blocker = 'Waiting for MIS Submission';
  } else {
    nextAction = 'Review Lead';
    blocker = 'None';
  }

  let currentStatusOptions = STATUS_MAP[l.bucket] || [];
  if (l.status && !currentStatusOptions.includes(l.status)) {
     currentStatusOptions = [l.status, ...currentStatusOptions];
  }
  let statusOptions = currentStatusOptions.map(s => `<option value="${s}" ${s === l.status ? 'selected' : ''}>${s}</option>`).join('');

  let currentSubOptions = SUBSTATUS_MAP[l.status] || [];
  if (l.subStatus && !currentSubOptions.includes(l.subStatus)) {
     currentSubOptions = [l.subStatus, ...currentSubOptions];
  }
  let subStatusOptions = currentSubOptions.map(s => `<option value="${s}" ${s === l.subStatus ? 'selected' : ''}>${s}</option>`).join('');

  let html = `
    <div class="card" style="padding: 24px 16px; border:none; box-shadow:0 4px 15px rgba(0,0,0,0.05); background:var(--white); border-radius:12px;">
      <div style="font-weight:700; margin-bottom:16px;">Update Status</div>
      <div style="display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-bottom:16px;">
        <div style="grid-column: span 2;">
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Status</label>
          <select class="form-control" style="padding:6px; font-size:12px;" id="update-status" onchange="document.getElementById('update-substatus').innerHTML = (SUBSTATUS_MAP[this.value] || []).map(s => '<option value=&quot;'+s+'&quot;>'+s+'</option>').join('')">
            ${statusOptions}
          </select>
        </div>
        <div style="grid-column: span 2;">
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Sub Status</label>
          <select class="form-control" style="padding:6px; font-size:12px;" id="update-substatus">
            ${subStatusOptions}
          </select>
        </div>
        <div>
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Follow-up Date</label>
          <input type="date" class="form-control" style="padding:6px; font-size:12px;" id="update-followup">
        </div>
        <div>
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Pending With</label>
          <select class="form-control" style="padding:6px; font-size:12px;" id="update-pending">
            <option>Customer</option>
            <option>IBM Agent</option>
            <option>Underwriter</option>
          </select>
        </div>
        <div style="grid-column: span 2;">
          <label style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase;">Remarks</label>
          <textarea class="form-control" rows="2" style="padding:6px; font-size:12px;" id="update-remarks"></textarea>
        </div>
      </div>
      <button class="btn btn-primary" style="width:100%; border-radius:8px;" onclick="saveStatusUpdate()">Update Status</button>
    </div>
  `;
  document.getElementById('detail-right').innerHTML = html;
}

function saveStatusUpdate() {
  const newStatus = document.getElementById('update-status').value;
  const newSubStatus = document.getElementById('update-substatus').value;
  const followUpDate = document.getElementById('update-followup').value;
  const pendingWith = document.getElementById('update-pending').value;
  const remarks = document.getElementById('update-remarks').value;

  const reqFollowUp = ['Call Back', 'Consent Pending', 'Payment Pending', 'Documents Pending'];
  if (reqFollowUp.includes(newStatus) && !followUpDate) {
    showToast('Follow-up date is mandatory for ' + newStatus, false);
    return;
  }

  if (newStatus === 'Payment Verified' && currentLead.bucket === 'Quote') {
     currentLead.paymentVerified = true;
     currentLead.productStatus = 'locked';
     currentLead.finalProduct = G_PRODUCT_TAB || 'lp';
     currentLead.finalInsurer = currentLead.selectedPlan ? currentLead.selectedPlan.insurer : 'CARE Health Insurance';
  }

  transitionLeadState(newStatus, newSubStatus, remarks, followUpDate, pendingWith);
}

