        <div style="position:absolute; top:12px; left:24px; width:${(step-1)*16.66}%; height:2px; background:var(--primary); z-index:0; transition:width 0.3s;"></div>

        ${['Generate', 'Select', 'Share', 'Link', 'Send Link', 'Proof', 'Verified'].map((label, idx) => `
          <div style="position:relative; z-index:1; text-align:center; width:60px;">
            <div style="width:24px; height:24px; border-radius:50%; background:${step > idx+1 ? 'var(--primary)' : step === idx+1 ? 'white' : 'white'}; border:2px solid ${step >= idx+1 ? 'var(--primary)' : '#E5E7EB'}; margin:0 auto 8px; display:flex; align-items:center; justify-content:center; color:${step > idx+1 ? 'white' : 'var(--primary)'}; font-size:10px; font-weight:700;">
              ${step > idx+1 ? '✓' : idx+1}
            </div>
            <div style="font-size:10px; font-weight:600; color:${step >= idx+1 ? 'var(--text-heading)' : 'var(--text-muted)'};">${label}</div>
