  let productTabsHtml = `
    <div style="display:flex; gap:8px; margin-bottom:16px;">
      ${['lp', 'property', 'credit', 'term'].map(p => `
        <button class="btn ${product===p ? 'btn-primary' : 'btn-ghost'}" style="flex:1; border:1px solid ${product===p?'var(--primary)':'#E5E7EB'};" onclick="showToast('Cannot switch products after locking')">${getProductLabel(p)}</button>
