function renderPipelineCards() {
  let counts = { total: LEADS.length, New: 0, Contacted: 0, Quote: 0, Processing: 0, Policy: 0, Lost: 0 };
  LEADS.forEach(l => { if(counts[l.bucket] !== undefined) counts[l.bucket]++; });

  const colors = {
    total: '#4B5563', New: '#3B82F6', Contacted: '#D97706', 
    Quote: '#473391', Processing: '#EA580C', Policy: '#16A34A', Lost: '#EF4444'
  };

  let html = '';
  Object.keys(counts).forEach(k => {
    let label = k === 'total' ? 'Total Active' : k;
    html += `
      <div class="card card-compact pipeline-card" style="border-top-color: ${colors[k]}">
        <div class="label" style="margin-bottom:4px;">${label}</div>
        <div style="font-size:24px; font-weight:700; color:${colors[k]}">${counts[k]}</div>
      </div>
    `;
  });
  document.getElementById('pipeline-cards').innerHTML = html;
}

