args.ReplacementContent:
function renderProcessingStage() {
  let product = currentLead.finalProduct || currentLead.initialProduct || 'lp';
  let insurer = currentLead.selectedPlan ? currentLead.selectedPlan.insurer : '';
  let isTata = insurer === 'TATA AIG';

  // Product-specific milestones with helper text
  let milestones = [];
  if (product === 'property') {
     milestones = [
       { label: 'Payment Verified', helper: 'Payment proof has been uploaded and verified by operations.' },
       { label: 'KYC Documents', helper: 'Upload Aadhaar + PAN copies for KYC verification.' },
       { label: 'Policy Issued', helper: 'Insurer issues the policy after KYC approval.' },
       { label: 'Policy Copy Received', helper: 'Soft copy of the policy document received from insurer.' }
     ];
  } else if (product === 'lp' && isTata) {
     milestones = [
       { label: 'Payment Verified', helper: 'Payment proof uploaded and verified.' },
       { label: 'Tele-PD Scheduled', helper: 'TATA AIG will schedule a tele-personal discussion with the customer.' },
       { label: 'Tele-PD Completed', helper: 'Tele-PD completed. Awaiting underwriting decision.' },
       { label: 'Policy Issued', helper: 'TATA AIG issues the policy after PD clearance.' },
       { label: 'Policy Copy Received', helper: 'Soft copy of the policy received.' }
     ];
  } else if (product === 'lp') {
     milestones = [
       { label: 'Payment Verified', helper: 'Payment proof uploaded and verified.' },
       { label: 'Verification', helper: 'CARE Health verifies customer details and eligibility.' },
       { label: 'Feder Form', helper: 'Customer signs the Feder declaration form.' },
       { label: 'Policy Issued', helper: 'CARE issues the policy after form submission.' },
       { label: 'Policy Copy Received', helper: 'Soft copy of the policy received.' }
     ];
  } else {
     // Credit Life & Term Plan
     milestones = [
       { label: 'Payment Verified', helper: 'Payment proof uploaded and verified.' },
       { label: 'KYC Verification', helper: 'Upload identity and address proof documents.' },
       { label: 'Income Verification', helper: 'Upload salary slips or ITR for income verification.' },
       { label: 'Medical Examination', helper: 'Customer undergoes medical tests as required by insurer.' },
       { label: 'Underwriting Review', helper: 'Insurer reviews all documents and medical reports.' },
       { label: 'Approval Decision', helper: 'Insurer issues approval, counter-offer, or rejection.' },
       { label: 'Policy Issued', helper: 'Policy issued after approval. Document will be shared.' }
     ];
  }

  // Proper status-to-milestone mapping matrix
  let activeIdx = 0;
  let status = currentLead.status;
  let subStatus = currentLead.subStatus;

  if (product === 'property') {
    // Property: 4 milestones
    if (status === 'Documents' && (subStatus === 'Pending' || subStatus === 'Partial')) activeIdx = 1;
    else if (status === 'Documents' && subStatus === 'Received') activeIdx = 2;
    else if (status === 'Policy Issuance' && subStatus === 'Pending') activeIdx = 2;
    else if (status === 'Policy Issuance' && subStatus === 'Issued') activeIdx = 3;
    else if (status === 'Documents') activeIdx = 1;
    else if (status === 'Approval') activeIdx = 2;
    else if (status === 'Policy Issuance') activeIdx = 2;
  } else if (product === 'lp') {
    // LP: 5 milestones
    if (status === 'Documents' && subStatus === 'Pending') activeIdx = 1;
    else if (status === 'Documents' && (subStatus === 'Partial' || subStatus === 'Received')) activeIdx = 2;
    else if (status === 'Medical') activeIdx = isTata ? 2 : 2;
    else if (status === 'Approval' && (subStatus === 'Pending' || subStatus === 'Counter Offer')) activeIdx = 3;
    else if (status === 'Approval' && (subStatus === 'Approved' || subStatus === 'Rejected')) activeIdx = 3;
    else if (status === 'Policy Issuance' && subStatus === 'Pending') activeIdx = 3;
    else if (status === 'Policy Issuance' && subStatus === 'Issued') activeIdx = 4;
    else if (status === 'Documents') activeIdx = 1;
    else if (status === 'Approval') activeIdx = 3;
    else if (status === 'Policy Issuance') activeIdx = 3;
  } else {
    // CL/Term: 7 milestones
    if (status === 'Documents' && subStatus === 'Pending') activeIdx = 1;
    else if (status === 'Documents' && subStatus === 'Partial') activeIdx = 2;
    else if (status === 'Documents' && subStatus === 'Received') activeIdx = 3;
    else if (status === 'Medical' && subStatus === 'Scheduled') activeIdx = 3;
    else if (status === 'Medical' && subStatus === 'Completed') activeIdx = 4;
    else if (status === 'Approval' && (subStatus === 'Pending' || subStatus === 'Counter Offer')) activeIdx = 4;
    else if (status === 'Approval' && subStatus === 'Approved') activeIdx = 5;
    else if (status === 'Approval' && subStatus === 'Rejected') activeIdx = 5;
    else if (status === 'Policy Issuance' && subStatus === 'Pending') activeIdx = 5;
    else if (status === 'Policy Issuance' && subStatus === 'Issued') activeIdx = 6;
    else if (status === 'Documents') activeIdx = 1;
    else if (status === 'Medical') activeIdx = 3;
    else if (status === 'Approval') activeIdx = 4;
    else if (status === 'Policy Issuance') activeIdx = 5;
  }

  // Payment Verified is always done (first milestone) when in Processing
  if (activeIdx === 0) activeIdx = 1;

  // Simulated completion dates for done milestones
  let baseDateMs = Date.now() - (activeIdx * 2 * 86400000); // 2 days apart

  let milestoneHtml = milestones.map((m, i) => {
     let isDone = i < activeIdx;
     let isActive = i === activeIdx;
     let isPending = !isDone && !isActive;
     let bg = isDone ? '#F0FDF4' : isActive ? '#EFF6FF' : 'transparent';
     let borderColor = isDone ? '#BBF7D0' : isActive ? '#BFDBFE' : '#E5E7EB';
     let dotBg = isDone ? '#10B981' : isActive ? 'var(--primary)' : 'white';
     let dotBorder = isDone ? '#10B981' : isActive ? 'var(--primary)' : '#D1D5DB';
     let icon = isDone ? '✓' : isActive ? (i+1) : (i+1);
     let dotColor = isDone || isActive ? 'white' : '#9CA3AF';

     // Simulated date for done milestones
     let doneDate = '';
     if (isDone) {
        let d = new Date(baseDateMs + (i * 2 * 86400000));
        doneDate = d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
