function showToast(msg, isSuccess=true) {
  const t = document.getElementById('toast');
  document.getElementById('toast-msg').innerText = msg;
  document.getElementById('toast-icon').innerText = isSuccess ? '✓' : 'ℹ';
  t.style.background = isSuccess ? '#16A34A' : '#1A1A2E';
  t.classList.add('show');
  setTimeout(() => t.classList.remove('show'), 2600);
}

// Modal JS Logic
function openStatusModal(leadId) {
  const lead = LEADS.find(l => l.id === leadId);
  document.getElementById('statusLeadId').value = lead.id;
  document.getElementById('statusCurrentBucket').value = lead.bucket;

  const config = STATE_MACHINE_CONFIG[lead.bucket];
  const statusSelect = document.getElementById('statusSelect');
  statusSelect.innerHTML = '<option value="">Select Status</option>';
  if (config) {
    Object.keys(config.statuses).forEach(status => {
      statusSelect.innerHTML += `<option value="${status}">${status}</option>`;
    });
  }

  document.getElementById('subStatusSelect').innerHTML = '<option value="">Select Sub Status</option>';
  document.getElementById('followUpGroup').style.display = 'none';
  document.getElementById('pendingWithGroup').style.display = 'none';
  document.getElementById('uploadGroup').style.display = 'none';
  document.getElementById('nextBucketLabel').innerText = lead.bucket;

  document.getElementById('statusModalOverlay').classList.add('open');
  document.getElementById('statusModal').style.display = 'block';
}

function handleStatusChange() {
  const bucket = document.getElementById('statusCurrentBucket').value;
  const status = document.getElementById('statusSelect').value;
  const subSelect = document.getElementById('subStatusSelect');

  subSelect.innerHTML = '<option value="">Select Sub Status</option>';
  if (!status) return;

  const statusConfig = STATE_MACHINE_CONFIG[bucket].statuses[status];
  statusConfig.subStatuses.forEach(sub => {
    subSelect.innerHTML += `<option value="${sub}">${sub}</option>`;
  });

  handleSubStatusChange();
}

function handleSubStatusChange() {
  const bucket = document.getElementById('statusCurrentBucket').value;
  const status = document.getElementById('statusSelect').value;
  const subStatus = document.getElementById('subStatusSelect').value;

  if (!status || !subStatus) return;

  const config = STATE_MACHINE_CONFIG[bucket].statuses[status];

  if (config.mandatoryFollowUp) {
    document.getElementById('followUpGroup').style.display = 'block';
    document.getElementById('followUpLabel').innerHTML = 'Follow-up Date <span style="color:var(--danger)">*</span>';
  } else {
    document.getElementById('followUpGroup').style.display = 'block';
    document.getElementById('followUpLabel').innerHTML = 'Follow-up Date (Optional)';
  }

  if (config.pendingWith && config.pendingWith !== 'None') {
    document.getElementById('pendingWithGroup').style.display = 'block';
    document.getElementById('pendingWithInput').value = config.pendingWith;
  } else {
    document.getElementById('pendingWithGroup').style.display = 'none';
  }

  let reqUpload = null;
  if (config.mandatoryUpload) reqUpload = config.mandatoryUpload(subStatus);
  if (reqUpload) {
    document.getElementById('uploadGroup').style.display = 'block';
    document.getElementById('uploadLabel').innerHTML = `${reqUpload} <span style="color:var(--danger)">*</span>`;
  } else {
    document.getElementById('uploadGroup').style.display = 'none';
  }

  let nextBucket = config.nextBucket;
  if (config.conditionNextBucket) {
    nextBucket = config.conditionNextBucket(subStatus);
  }
  document.getElementById('nextBucketLabel').innerText = nextBucket;
}

function closeStatusModal() {
  document.getElementById('statusModalOverlay').classList.remove('open');
  document.getElementById('statusModal').style.display = 'none';
}

function saveStatusUpdate() {
  const id = document.getElementById('statusLeadId').value;
  const status = document.getElementById('statusSelect').value;
  const subStatus = document.getElementById('subStatusSelect').value;
  const nextBucket = document.getElementById('nextBucketLabel').innerText;
  const fupInput = document.getElementById('followUpInput').value;

  if (!status || !subStatus) {
    alert("Please select Status and Sub Status."); return;
  }

  const config = STATE_MACHINE_CONFIG[document.getElementById('statusCurrentBucket').value].statuses[status];
  if (config.mandatoryFollowUp && !fupInput) {
    alert("Follow-up date is mandatory for this status."); return;
  }

  const lead = LEADS.find(l => l.id === id);
  lead.bucket = nextBucket;
  lead.status = status;
  lead.subStatus = subStatus;

  if (fupInput) {
    let dateObj = new Date(fupInput);
    lead.followUpDate = dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: '2-digit', minute:'2-digit' });
  }

  lead.log.unshift({ dot: '#473391', text: `Status updated to ${status} - ${subStatus}`, time: 'Just now' });

  closeStatusModal();
  renderLeadTable();
  showToast('Status Updated Successfully!');
}

