function saveStatusUpdate() {
  const newStatus = document.getElementById('update-status').value;
  const newSubStatus = document.getElementById('update-substatus').value;

  // Dynamic fields extraction
  const remarksEl = document.getElementById('update-remarks');
  const remarks = remarksEl ? remarksEl.value : '';

  let followUpDate = '', followUpTime = '';
  if (newStatus === 'Not Connected' || newStatus === 'Callback') {
    followUpDate = document.getElementById('update-fdate').value;
    followUpTime = document.getElementById('update-ftime').value;
    if (!followUpDate || !followUpTime) {
      showToast('Follow-up Date and Time are mandatory', false);
      return;
    }
  }

  if (newStatus === 'Payment Done' && newSubStatus === 'Payment Verified') {
    const proof = document.getElementById('update-proof') ? document.getElementById('update-proof').value : '';
    if (!proof) {
      showToast('Payment proof upload is mandatory', false);
      return;
    }
  }

  if ((newStatus === 'Counter Offer') || (newStatus === 'Payment Done' && newSubStatus === 'Verification Failed')) {
    if (!remarks.trim()) {
      showToast('Remarks are mandatory for this status update', false);
      return;
    }
  }

  if (newStatus === 'Policy Issued') {
    const doc = document.getElementById('update-policy').value;
    if (!doc) {
      showToast('Policy document upload is mandatory', false);
      return;
    }
  }

  if (newStatus === 'Counter Offer' && newSubStatus === 'Accepted' && !remarks.trim()) {
    showToast('Remarks are mandatory when accepting a counter offer', false);
    return;
  }

  if (newStatus === 'Payment Done' && newSubStatus === 'Payment Verified' && currentLead.bucket === 'Quote') {
     currentLead.paymentVerified = true;
     currentLead.productStatus = 'locked';
     currentLead.finalProduct = G_PRODUCT_TAB || 'lp';
     currentLead.finalInsurer = currentLead.selectedPlan ? currentLead.selectedPlan.insurer : 'CARE Health Insurance';
  }

  transitionLeadState(newStatus, newSubStatus, remarks, followUpDate, '');

  // Task Engine logic
  if (newStatus === 'Not Connected' || newStatus === 'Callback') {
    if (!window.G_TASKS) window.G_TASKS = [];
    window.G_TASKS.push({
      id: 'task_' + Date.now(),
      leadId: currentLead.id,
      leadName: currentLead.name,
      taskType: newStatus,
      date: followUpDate,
      time: followUpTime,
      status: 'pending'
    });
    showToast('Follow-up Task Created Automatically');
  }
}

