function renderActionCenter() {
  const l = currentLead;
  const bucket = l.bucket || 'New';
  const status = l.status || 'Fresh';
  const subStatus = l.subStatus || '-';
  const config = STATE_MACHINE_CONFIG[bucket];

  // Derive pending with
  let pendingWith = 'IBM Agent';
  if (config && config.statuses && config.statuses[status]) {
    pendingWith = config.statuses[status].pendingWith || 'IBM Agent';
  }

  // Derive next recommended action
  let nextAction = 'Review lead and take next step.';
  if (bucket === 'New') {
    nextAction = 'Call customer to pitch ' + getProductLabel(l.finalProduct || l.initialProduct) + '.';
  } else if (bucket === 'Contacted') {
    if (status === 'Call Back') nextAction = 'Follow up with customer as scheduled.';
    else if (status === 'Interested') nextAction = 'Generate and share insurance quote.';
    else nextAction = 'Re-engage customer and understand interest level.';
  } else if (bucket === 'Quote') {
    if (status === 'Quote Shared') nextAction = 'Follow up and confirm selected insurer.';
    else if (status === 'Payment Link Shared') nextAction = 'Confirm customer has completed payment.';
    else nextAction = 'Share quote with customer via WhatsApp.';
  } else if (bucket === 'Payment Done') {
    nextAction = 'Track processing milestones and ensure timely completion.';
  } else if (bucket === 'Policy') {
    nextAction = 'Share policy document and confirm customer acknowledgment.';
  }

  let followUp = l.followUpDate || 'No follow-up scheduled';
  let fupColor = followUp.toLowerCase().includes('overdue') ? '#DC2626' : followUp.toLowerCase().includes('today') ? '#D97706' : '#111827';

  return `
    <div style="background:white; border-left:4px solid var(--primary); border-radius:8px; padding:20px; margin-bottom:20px; box-shadow:0 2px 8px rgba(0,0,0,0.06);">
      <div style="font-weight:700; font-size:15px; color:var(--text-heading); margin-bottom:16px;">Lead Action Center</div>
      <div style="display:grid; grid-template-columns:1fr 1fr 1fr 1fr; gap:16px; margin-bottom:16px;">
        <div>
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.5px; margin-bottom:4px;">Current Status</div>
          <div style="font-weight:700; font-size:14px; color:var(--primary);">${status}</div>
        </div>
        <div>
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.5px; margin-bottom:4px;">Sub Status</div>
          <div style="font-weight:600; font-size:14px; color:var(--text-heading);">${subStatus}</div>
        </div>
        <div>
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.5px; margin-bottom:4px;">Pending With</div>
          <div style="font-weight:600; font-size:14px; color:var(--text-heading);">${pendingWith}</div>
        </div>
        <div>
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.5px; margin-bottom:4px;">Follow-up</div>
          <div style="font-weight:600; font-size:14px; color:${fupColor};">${followUp}</div>
        </div>
      </div>
      <div style="background:#F8F7FF; border-radius:6px; padding:12px 16px; display:flex; align-items:center; gap:10px;">
        <div style="font-size:18px;">💡</div>
        <div>
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.5px;">Next Recommended Action</div>
          <div style="font-weight:600; font-size:13px; color:var(--primary);">${nextAction}</div>
        </div>
      </div>
    </div>
  `;
}

