  // --- Lead Health Widget (Change 3) ---
  let lastActivity = l.log[0]?.time || 'Unknown';
  let pendingSince = '1 Day';
  let pendingWith = 'IBM Agent';
  if (config && config.statuses && config.statuses[l.status]) {
    pendingWith = config.statuses[l.status].pendingWith || 'IBM Agent';
  }

  // Risk calculation from log time
  let risk = 'Low';
  let riskColor = '#10B981';
  let riskBg = '#F0FDF4';
  let riskBorder = '#BBF7D0';
  let riskIcon = '🟢';
