  if (logTime.includes('day') || logTime.includes('ago')) {
    let dayMatch = logTime.match(/(\d+)\s*day/);
    if (dayMatch) {
      let days = parseInt(dayMatch[1]);
      pendingSince = days + ' Days';
      if (days >= 5) { risk = 'High'; riskColor = '#DC2626'; riskBg = '#FEF2F2'; riskBorder = '#FECACA'; riskIcon = '🔴'; }
      else if (days >= 3) { risk = 'Medium'; riskColor = '#D97706'; riskBg = '#FFFBEB'; riskBorder = '#FDE68A'; riskIcon = '🟡'; }
    }
  }
  if (logTime.includes('just now') || logTime.includes('mins') || logTime.includes('hr')) {
    pendingSince = 'Today';
  }

  let healthHtml = `
