        </div>
        <div style="background:#F9FAFB; border-radius:6px; padding:10px;">
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; margin-bottom:2px;">Last Activity</div>
          <div style="font-weight:600; font-size:13px; color:var(--text-heading);">${lastActivity}</div>
        </div>
        <div style="background:#F9FAFB; border-radius:6px; padding:10px;">
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; margin-bottom:2px;">Pending Since</div>
          <div style="font-weight:600; font-size:13px; color:var(--text-heading);">${pendingSince}</div>
        </div>
        <div style="background:#F9FAFB; border-radius:6px; padding:10px;">
          <div style="font-size:10px; font-weight:600; color:var(--text-muted); text-transform:uppercase; margin-bottom:2px;">Pending With</div>
          <div style="font-weight:600; font-size:13px; color:var(--text-heading);">${pendingWith}</div>
        </div>
      </div>
    </div>
  `;

  // --- Follow-up Widget (Change 8) ---
  let followUp = l.followUpDate || '';
  let fupReason = l.subStatus || l.status || '-';
  let fupPending = pendingWith;
  let fupColor = '#111827';
  let fupBg = '#F9FAFB';
  let fupBorder = '#E5E7EB';
  let fupIconBg = '#F3F4F6';

  if (followUp.toLowerCase().includes('overdue')) {
    fupColor = '#DC2626'; fupBg = '#FEF2F2'; fupBorder = '#FECACA'; fupIconBg = '#FEE2E2';
  } else if (followUp.toLowerCase().includes('today') || followUp.toLowerCase().includes('tomorrow')) {
    fupColor = '#D97706'; fupBg = '#FFFBEB'; fupBorder = '#FDE68A'; fupIconBg = '#FEF3C7';
  }

  let followUpHtml = `
    <div class="card" style="padding:16px; border:1px solid ${fupBorder}; background:${fupBg}; box-shadow:none; border-radius:12px; margin-bottom:16px;">
