      otherUpdates.push(entry);
    }
  });

  let historyMode = currentLead.historyMode || 'timeline';

  let groupedHtml = '';

  function renderGroupSection(title, icon, entries, color) {
    if (entries.length === 0) return '';
    return `
      <div style="margin-bottom:20px;">
        <div style="display:flex; align-items:center; gap:8px; margin-bottom:10px; padding-bottom:8px; border-bottom:1px solid #F3F4F6;">
