function renderCenterPanel() {
  const l = currentLead;
  let activeTab = l.activeTab || 'History';

  let stages = ['New', 'Contacted', 'Quote', 'Payment Done', 'Policy'];
  let currentStageIndex = stages.indexOf(l.bucket);
  if(currentStageIndex === -1) currentStageIndex = 0;

  let stageHtml = stages.map((s, idx) => {
    let isActive = idx === currentStageIndex;
    let isCompleted = idx < currentStageIndex;
    let bg = 'white';
    let text = '#9CA3AF';
    let border = '1px solid #E5E7EB';

    if(isActive) {
       bg = '#473391'; text = 'white'; border = '1px solid #473391';
    } else if (isCompleted) {
       bg = '#F0EEFB'; text = '#473391'; border = '1px solid #F0EEFB';
    }

    let chevron = `<div style="background: ${bg}; color: ${text}; border: ${border}; border-radius: 4px; padding: 6px 14px; font-size: 12px; font-weight: 600;">${s}</div>`;
    let arrow = idx < stages.length - 1 ? `<div style="color: #D1D5DB; margin: 0 8px; font-weight: 700;">></div>` : '';
    return chevron + arrow;
  }).join('');

  let tabsHtml = `
    <div style="display: flex; gap: 20px; border-bottom: 1px solid #E5E7EB; padding: 0 20px;">
      <div onclick="currentLead.activeTab='History'; renderLeadDetail();" style="padding: 10px 16px; font-size: 13px; font-weight: 600; cursor: pointer; color: ${activeTab === 'History' ? '#473391' : '#9CA3AF'}; border-bottom: ${activeTab === 'History' ? '2px solid #473391' : 'none'};">Activity History</div>
      <div onclick="currentLead.activeTab='FollowUp'; renderLeadDetail();" style="padding: 10px 16px; font-size: 13px; font-weight: 600; cursor: pointer; color: ${activeTab === 'FollowUp' ? '#473391' : '#9CA3AF'}; border-bottom: ${activeTab === 'FollowUp' ? '2px solid #473391' : 'none'};">Follow Up</div>
      <div onclick="currentLead.activeTab='Documents'; renderLeadDetail();" style="padding: 10px 16px; font-size: 13px; font-weight: 600; cursor: pointer; color: ${activeTab === 'Documents' ? '#473391' : '#9CA3AF'}; border-bottom: ${activeTab === 'Documents' ? '2px solid #473391' : 'none'};">Documents</div>
    </div>
  `;

  let contentHtml = '';
  if(activeTab === 'History') {
    contentHtml = `
      <div style="padding: 20px;">
        <div style="background: white; border: 1px solid #E5E7EB; border-radius: 8px; padding: 14px 16px; margin-bottom: 10px;">
          <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px;">
            <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF;">System Update</div>
            <div style="font-size: 11px; font-weight: 600; color: #473391;">By Verification Agent</div>
          </div>
          <div style="font-size: 13px; font-weight: 600; color: #111827; margin-bottom: 4px;">Call attempt: Not connected</div>
          <div style="font-size: 12px; color: #4B5563; margin-bottom: 12px;">Automatic call attempt triggered. Customer did not pick up.</div>
          <div style="display: flex; justify-content: space-between; align-items: center;">
            <div style="font-size: 11px; color: #9CA3AF;">At Yesterday</div>
            <div style="font-size: 11px; color: #473391;">From Sangam</div>
          </div>
        </div>
      </div>
    `;
  } else if (activeTab === 'FollowUp') {
    contentHtml = `
      <div style="padding: 20px; display: flex; flex-direction: column; align-items: center; justify-content: center; margin-top: 40px;">
        <div style="width: 80px; height: 80px; background: #F3F4F6; border-radius: 16px; margin-bottom: 16px;"></div>
        <div style="font-size: 13px; font-weight: 600; color: #6B7280; margin-bottom: 4px;">No follow-up scheduled</div>
        <div style="font-size: 12px; color: #9CA3AF;">Set a follow-up date from the Update Status panel on the right.</div>
      </div>
    `;
  } else if (activeTab === 'Documents') {
    contentHtml = `
      <div style="padding: 20px; display: flex; flex-direction: column; align-items: center; justify-content: center; margin-top: 40px;">
        <div style="width: 80px; height: 80px; background: #F3F4F6; border-radius: 16px; margin-bottom: 16px;"></div>
        <div style="font-size: 13px; font-weight: 600; color: #6B7280; margin-bottom: 4px;">No documents uploaded yet</div>
        <div style="font-size: 12px; color: #9CA3AF;">Documents will appear here once uploaded.</div>
      </div>
    `;
  }

  let html = `
    <div style="background: white; border-bottom: 1px solid #E5E7EB; padding: 14px 20px; display: flex; justify-content: space-between; align-items: center;">
      <div style="display: flex; align-items: center;">
