  if (G_SECTION) {
    contentHtml = renderSectionForm(G_SECTION);
    el.innerHTML = contentHtml;
    return;
  }

  let trackerHtml = renderStageBar();

  if (currentLead.bucket === 'New') {
    contentHtml = renderNewStage();
  } else if (currentLead.bucket === 'Contacted') {
    contentHtml = renderContactedStage();
  } else if (currentLead.bucket === 'Payment Done') {
    contentHtml = renderPaymentDoneStage();
  } else if (currentLead.bucket === 'Quote') {
    contentHtml = renderQuoteStage();
  } else if (currentLead.bucket === 'Policy') {
    contentHtml = renderPolicyStage();
  } else if (currentLead.bucket === 'Lost') {
    contentHtml = renderLostStage();
