    options = ['Busy Call Later', 'Partial Discussion', 'Language Barrier', 'Customer Disconnected'];
  } else if (status === 'Interested') {
    options = ['Need Quote'];
  } else if (status === 'Not Interested') {
    options = ['Too Expensive', 'Already Insured', 'Not Required', 'Family Not Interested', 'Will Decide Later', 'Other'];
  }

  subSelect.innerHTML = options.map(o => `<option value="${o}">${o}</option>`).join('');

  window.handleDetailSubStatusChange();
};

