window.handleDetailStatusChange = function(preselectSubStatus) {
  if(!currentLead) return;
  const bucket = currentLead.bucket || 'New';
  const status = document.getElementById('detail-status').value;
  const subSelect = document.getElementById('detail-substatus');

  subSelect.innerHTML = '<option value="">Select Sub Status</option>';
  document.getElementById('detail-fup-wrapper').style.display = 'none';

  if (!status) return;

  const config = STATE_MACHINE_CONFIG[bucket].statuses[status];
  if (config && config.subStatuses) {
    config.subStatuses.forEach(s => {
      const selected = (s === preselectSubStatus) ? 'selected' : '';
      subSelect.innerHTML += `<option value="${s}" ${selected}>${s}</option>`;
    });
  }
  if(preselectSubStatus) window.handleDetailSubStatusChange();
};

window.handleDetailSubStatusChange = function() {
  if(!currentLead) return;
  const bucket = currentLead.bucket || 'New';
  const status = document.getElementById('detail-status').value;
  const subStatus = document.getElementById('detail-substatus').value;

  if (!status || !subStatus) return;

  const config = STATE_MACHINE_CONFIG[bucket].statuses[status];
  if (config.mandatoryFollowUp) {
    document.getElementById('detail-fup-wrapper').style.display = 'flex';
  } else {
    document.getElementById('detail-fup-wrapper').style.display = 'none';
  }

  if (config.pendingWith && config.pendingWith !== 'None') {
    document.getElementById('detail-pending-with').value = config.pendingWith;
  }

  if (config.mandatoryUpload && typeof config.mandatoryUpload === 'function') {
    const uploadLabel = config.mandatoryUpload(subStatus);
    if (uploadLabel) {
      document.getElementById('detail-upload-wrapper').style.display = 'flex';
      document.getElementById('detail-upload-label').innerText = uploadLabel.toUpperCase() + ' *';
      if (uploadLabel === 'Payment Proof') {
         document.getElementById('detailPaymentProofFields').style.display = 'flex';
      } else {
         document.getElementById('detailPaymentProofFields').style.display = 'none';
      }
    } else {
      document.getElementById('detail-upload-wrapper').style.display = 'none';
    }
  } else {
    document.getElementById('detail-upload-wrapper').style.display = 'none';
  }

  if (config.captureCounterOffer && typeof config.captureCounterOffer === 'function') {
    const showCO = config.captureCounterOffer(subStatus);
    if (showCO) {
      document.getElementById('detail-co-wrapper').style.display = 'flex';
    } else {
      document.getElementById('detail-co-wrapper').style.display = 'none';
    }
  } else {
    document.getElementById('detail-co-wrapper').style.display = 'none';
  }
};

