window.handleDetailSubStatusChange = function() {
  if(!currentLead) return;
  const status = document.getElementById('detail-status').value;
  const fupWrapper = document.getElementById('detail-fup-wrapper');
  const payWrapper = document.getElementById('detail-payment-verification-wrapper');

  const bucketConfig = STATE_MACHINE_CONFIG[currentLead.bucket || 'New'];
  const statusConfig = bucketConfig.statuses[status];

  if (statusConfig && statusConfig.mandatoryFollowUp) {
    fupWrapper.style.display = 'flex';
  } else {
    fupWrapper.style.display = 'none';
  }

  if (status === 'Payment Done') {
    if(payWrapper) payWrapper.style.display = 'flex';
  } else {
    if(payWrapper) payWrapper.style.display = 'none';
  }

  window.validatePaymentFields();
};

window.validatePaymentFields = function() {
  const status = document.getElementById('detail-status').value;
  const btn = document.getElementById('detail-update-status-btn');
  const note = document.getElementById('detail-payment-verification-note');
  if(!btn) return;

  if (status === 'Payment Done') {
    const amt = document.getElementById('detail-pay-amount').value;
    const utr = document.getElementById('detail-pay-utr').value;
    const date = document.getElementById('detail-pay-date').value;
    const proof = document.getElementById('detail-pay-proof').value;

    if (amt && utr && date && proof) {
      btn.disabled = false;
      btn.style.opacity = '1';
      btn.style.cursor = 'pointer';
      if(note) note.style.display = 'none';
    } else {
      btn.disabled = true;
      btn.style.opacity = '0.5';
      btn.style.cursor = 'not-allowed';
      if(note) note.style.display = 'block';
    }
  } else {
    btn.disabled = false;
    btn.style.opacity = '1';
    btn.style.cursor = 'pointer';
    if(note) note.style.display = 'none';
  }
};

