  currentLead.quoteState.paymentLinkShared = false;
  currentLead.finalInsurer = null;
  currentLead.productStatus = 'draft';
  renderLeadDetail();
};

window.handlePaymentLinkInput = function() {
  if(!currentLead || !currentLead.quoteState) return;
  const val = document.getElementById('payment-link-input').value;
  currentLead.quoteState.paymentLink = val;
  const btnWa = document.getElementById('btn-share-pay-wa');
  const btnEmail = document.getElementById('btn-share-pay-email');

  if (val.trim() !== '') {
    if(btnWa) { btnWa.style.opacity = '1'; btnWa.style.cursor = 'pointer'; }
    if(btnEmail) { btnEmail.style.opacity = '1'; btnEmail.style.cursor = 'pointer'; }
  } else {
    if(btnWa) { btnWa.style.opacity = '0.4'; btnWa.style.cursor = 'not-allowed'; }
    if(btnEmail) { btnEmail.style.opacity = '0.4'; btnEmail.style.cursor = 'not-allowed'; }
  }
};

window.sharePaymentLink = function(channel) {
  if(!currentLead || !currentLead.quoteState || !currentLead.quoteState.paymentLink) return;
  if(currentLead.quoteState.paymentLink.trim() === '') return;

  currentLead.quoteState.paymentLinkShared = true;

  const statusSelect = document.getElementById('detail-status');
  if(statusSelect) statusSelect.value = 'Payment Link Shared';
  handleDetailStatusChange();
  const subSelect = document.getElementById('detail-substatus');
  if(subSelect) subSelect.value = 'Awaiting Payment';
  handleDetailSubStatusChange();

  if(!currentLead.history) currentLead.history = [];
  currentLead.history.unshift({
    type: 'Agent Update',
    agent: 'Verification Agent',
    title: `Payment link shared with customer via ${channel}`,
    desc: `${currentLead.quoteState.lockedPlan.insurer}`,
    time: 'Just now'
  });

  renderLeadDetail();

  const toast = document.createElement('div');
  toast.style.position = 'absolute';
  toast.style.top = '16px';
  toast.style.left = '50%';
  toast.style.transform = 'translateX(-50%)';
  toast.style.background = '#E6F4ED';
  toast.style.color = '#1A7A4A';
  toast.style.padding = '8px 14px';
  toast.style.borderRadius = '6px';
  toast.style.fontSize = '12px';
  toast.style.fontWeight = '600';
  toast.style.zIndex = '100';
  toast.style.boxShadow = '0 4px 6px rgba(0,0,0,0.1)';
  toast.innerText = 'Payment link sent successfully';

  const center = document.getElementById('detail-center');
  if(center) {
    center.appendChild(toast);
    setTimeout(() => {
      if(toast.parentNode) toast.parentNode.removeChild(toast);
    }, 3000);
  }
};

window.resendPaymentLink = function() {
  if(!currentLead || !currentLead.quoteState) return;
  currentLead.quoteState.paymentLinkShared = false;
  renderLeadDetail();
};

