window.CURRENT_ROLE = 'MANAGER';
window.bulkAssignMode = false;
window.selectedLeadsForAssign = new Set();

// === DATA (Mock) ===

function renderLeadTable() {
  let thead = document.getElementById('sangam-table-head');
  let tbody = document.getElementById('lead-table-body');
  let thHtml = `<tr>`;

  let allSelected = LEADS.length > 0 && window.selectedLeadsForAssign.size === LEADS.length;
  let someSelected = window.selectedLeadsForAssign.size > 0 && !allSelected;
  let headerCbBg = allSelected ? '#473391' : (someSelected ? '#473391' : 'transparent');
  let headerCbBorder = (allSelected || someSelected) ? '#473391' : '#C5C0F5';
  let headerTickHtml = allSelected ? `<svg width="10" height="8" viewBox="0 0 10 8" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M1 4L3.5 6.5L9 1" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>` : 
                       (someSelected ? `<svg width="10" height="2" viewBox="0 0 10 2" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M1 1H9" stroke="white" stroke-width="2" stroke-linecap="round"/></svg>` : '');

  if (window.bulkAssignMode) {
     thHtml += `<th style="width:40px;"><div style="width:16px; height:16px; border:2px solid ${headerCbBorder}; border-radius:3px; background:${headerCbBg}; display:flex; align-items:center; justify-content:center; cursor:pointer;" onclick="toggleSelectAll()">${headerTickHtml}</div></th>`;
  }

  thHtml += `
    <th style="width: 100px;">INSURANCE ID</th>
    <th style="width: 160px;">CUSTOMER</th>
    <th style="width: 140px;">PRODUCT</th>
    <th style="width: 130px;">LOAN</th>
    <th style="width: 180px;">STAGE & STATUS</th>
    <th style="width: 120px;">SOURCE / SUB SOURCE</th>
    <th style="width: 120px;">PARTNER</th>
    <th style="width: 100px;">RM</th>
    <th style="width: 140px;">NEXT FOLLOW-UP</th>
    <th style="width: 110px;">CREATED AT</th>
  `;
  if (window.CURRENT_ROLE === 'MANAGER') {
    thHtml += `<th style="width: 110px;">ASSIGN TO</th>`;
  }
  thHtml += `</tr>`;
  if(thead) thead.innerHTML = thHtml;

  // Update Banner State
  const banner = document.getElementById('bulk-assign-banner');
  if (banner) {
      if (window.bulkAssignMode) {
          banner.style.display = 'flex';
          document.getElementById('bulk-assign-count').textContent = `Showing ${LEADS.length} leads · ${window.selectedLeadsForAssign.size} selected`;
          const assignBtn = document.getElementById('bulk-assign-action-btn');
          if (window.selectedLeadsForAssign.size > 0) {
              assignBtn.style.display = 'block';
              assignBtn.textContent = `Assign ${window.selectedLeadsForAssign.size} Leads →`;
          } else {
              assignBtn.style.display = 'none';
          }
      } else {
          banner.style.display = 'none';
      }
  }

  let html = '';

  LEADS.forEach(l => {
    let siText = l.si ? formatLakhs(l.si) : `<span class="loan-missing">missing</span>`;
    let bankText = l.hlLead ? l.hlLead.bank : (l.loanBank || 'Unknown Bank');
    let hlStage = l.hlLead ? l.hlLead.hlStage : '-';
    let statusText = l.status || '-';
    let subStatusText = l.subStatus ? `(${l.subStatus})` : '';

    let insurer = l.finalInsurer || (l.selectedPlan ? l.selectedPlan.insurer : '');
    let insurerText = insurer ? insurer : 'Unassigned';

    // Calculate Lead Age
    let leadAge = 'Just now';
    if (l.createdAt) {
       let diffMs = Date.now() - new Date(l.createdAt).getTime();
       let diffDays = Math.floor(diffMs / 86400000);
       if (diffDays === 0) leadAge = 'Today';
       else if (diffDays === 1) leadAge = '1 Day';
       else leadAge = `${diffDays} Days`;
    }

    // Calculate Priority Logic
    let priority = '⚪ Cold';
    let isHot = false;
    let isWarm = false;
    let fupLower = (l.followUpDate || '').toLowerCase();

    if (l.status === 'Interested' && fupLower.includes('today')) isHot = true;
    if (l.status === 'Quote Shared' || l.status === 'Payment Pending') isHot = true;

    if (!isHot && l.status === 'Not Connected') isWarm = true;

    if (isHot) priority = '🔥 Hot';
    else if (isWarm) priority = '🟡 Warm';
    else priority = '⚪ Cold';

    let nextFup = l.followUpDate || 'No Follow-up';
    let fupColor = nextFup.toLowerCase().includes('overdue') ? '#DC2626' : 'inherit';

    const bucketBgMap = { 'New': '#EFF6FF', 'Contacted': '#FFFBEB', 'Quote': '#EEEDFE', 'Payment Done': '#F0FDFA', 'Policy': '#F0FDF4', 'Lost': '#FEF2F2' };
    const bucketColorMap = { 'New': '#1E40AF', 'Contacted': '#B45309', 'Quote': '#4C1D95', 'Payment Done': '#0F766E', 'Policy': '#15803D', 'Lost': '#991B1B' };
    let bBg = bucketBgMap[l.bucket] || '#F3F4F6';
    let bColor = bucketColorMap[l.bucket] || 'var(--text-heading)';

    const displaySource = l.source || 'Manual';
    const displaySubSource = l.subSource || '—';
    const displayPartner = l.partner || 'E2E Sales';
    const displayRM = (l.hlLead && l.hlLead.rm) ? l.hlLead.rm : 'Ambak BM';

    let displayDate = '15 Jun, 2026 10:00 AM';
    let relativeTime = 'Just now';
    if(l.createdAt) {
       const dateObj = new Date(l.createdAt);
       if(!isNaN(dateObj.getTime())) {
           const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
           const d = dateObj.getDate();
           const m = months[dateObj.getMonth()];
           const y = dateObj.getFullYear();
           let hr = dateObj.getHours();
           const min = dateObj.getMinutes().toString().padStart(2, '0');
           const ampm = hr >= 12 ? 'PM' : 'AM';
           hr = hr % 12 || 12;
           displayDate = `${d} ${m}, ${y} ${hr}:${min} ${ampm}`;

           let diffMs = Date.now() - dateObj.getTime();
           let diffDays = Math.floor(diffMs / 86400000);
           if(diffDays === 0) relativeTime = 'Just now';
           else if(diffDays === 1) relativeTime = 'Yesterday';
           else relativeTime = `${diffDays} days ago`;
       } else {
           displayDate = l.createdAt;
       }
    }

    let isSelectedRow = window.bulkAssignMode && window.selectedLeadsForAssign.has(l.id);
    let rowBg = isSelectedRow ? '#F0EEFB' : '';
    let rowBorder = isSelectedRow ? 'box-shadow: inset 3px 0 0 0 #473391;' : '';
    let rowClickAction = window.bulkAssignMode ? `toggleRowSelection('${l.id}')` : `openLead('${l.id}')`;

    let selectTdHtml = '';
    if (window.bulkAssignMode) {
       const cbBg = isSelectedRow ? '#473391' : 'transparent';
       const cbBorder = isSelectedRow ? '#473391' : '#C5C0F5';
       const tickHtml = isSelectedRow ? `<svg width="10" height="8" viewBox="0 0 10 8" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M1 4L3.5 6.5L9 1" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>` : '';
       selectTdHtml = `<td><div style="width:16px; height:16px; border:2px solid ${cbBorder}; border-radius:3px; background:${cbBg}; display:flex; align-items:center; justify-content:center;">${tickHtml}</div></td>`;
    }

    html += `
      <tr onclick="${rowClickAction}" style="cursor:pointer; background:${rowBg}; ${rowBorder}" class="table-row-hover">
        ${selectTdHtml}
        <td>
          <div style="font-weight:700; color:var(--primary);">${l.id}</div>
        </td>
        <td>
          <div class="lead-name" style="font-weight:600; color:var(--text-heading);">${l.name}</div>
          <div class="lead-phone" style="font-size:12px; color:var(--text-muted);">${l.phone}</div>
        </td>
        <td>
          <div style="font-weight:600;">${getProductLabel(l.finalProduct || l.initialProduct)}</div>
          <div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${insurerText}</div>
        </td>
        <td>
          <div style="font-weight:600">${l.si ? formatLakhs(l.si) : '—'}</div>
          <div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${bankText}</div>
          <div style="font-size:11px; color:var(--text-muted); margin-top:2px; font-weight:500;">${hlStage}</div>
        </td>
        <td>
          <span class="badge" style="background:${bBg}; color:${bColor}; margin-bottom: 4px; display: inline-flex;">${l.bucket}</span>
          <div style="font-weight:600; font-size:13px; color:var(--text-heading);">${statusText}</div>
        </td>
        <td>
          <div style="font-weight:600; font-size:13px; color:var(--text-heading); text-transform:capitalize;">${displaySource}</div>
          <div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${displaySubSource}</div>
        </td>
        <td>
          <div style="font-weight:500; font-size:13px; color:var(--text-heading);">${displayPartner}</div>
        </td>
        <td>
          <div style="font-weight:500; font-size:13px; color:var(--text-heading);">${displayRM}</div>
        </td>
        <td>
           <div style="font-weight:600; font-size:13px; color:${fupColor};">${nextFup}</div>
        </td>
        <td>
           <div style="font-size:13px; color:var(--text-heading);">${displayDate}</div>
           <div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${relativeTime}</div>
        </td>
    `;

    if (window.CURRENT_ROLE === 'MANAGER') {
        html += `
        <td>
           <select class="search-input" style="min-width:100px; font-size:12px; font-weight:600; padding:4px 8px; height:auto; margin:0; border-radius:6px; cursor:pointer;" onclick="event.stopPropagation()">
             <option>Rohit M</option>
             <option>Priya S</option>
           </select>
        </td>
        `;
    }

    html += `</tr>`;
  });
  if(tbody) tbody.innerHTML = html;
  const ec = document.getElementById('entry-count');
  if(ec) ec.textContent = LEADS.length;
}

