function toggleRowSelection(id) {
  if(window.selectedLeadsForAssign.has(id)) {
    window.selectedLeadsForAssign.delete(id);
  } else {
    window.selectedLeadsForAssign.add(id);
  }
  renderLeadTable();
}

function toggleSelectAll() {
  if(window.selectedLeadsForAssign.size === LEADS.length && LEADS.length > 0) {
    window.selectedLeadsForAssign.clear();
  } else {
    LEADS.forEach(l => window.selectedLeadsForAssign.add(l.id));
  }
  renderLeadTable();
}

function openBulkAssignModal() {
  document.getElementById('bulk-assign-summary-text').textContent = `You are reassigning ${window.selectedLeadsForAssign.size} leads`;
  let pillsHtml = '';
  const selectedArr = Array.from(window.selectedLeadsForAssign);
  for(let i=0; i<Math.min(3, selectedArr.length); i++) {
     pillsHtml += `<div style="background:#F0EEFB; color:#473391; font-size:11px; font-weight:700; border-radius:4px; padding:2px 8px;">${selectedArr[i]}</div>`;
  }
  if(selectedArr.length > 3) {
     pillsHtml += `<div style="font-size:11px; color:#9CA3AF; margin-left:4px; display:flex; align-items:center;">+${selectedArr.length - 3} more</div>`;
  }
  document.getElementById('bulk-assign-pills').innerHTML = pillsHtml;

  document.getElementById('bulkAssignAgentSelect').value = '';
  document.getElementById('confirmBulkAssignBtn').style.opacity = '0.4';
  document.getElementById('confirmBulkAssignBtn').disabled = true;

  document.getElementById('bulkAssignOverlay').classList.add('open');
  document.getElementById('bulkAssignModal').style.display = 'flex';
}

function closeBulkAssignModal() {
  document.getElementById('bulkAssignOverlay').classList.remove('open');
  document.getElementById('bulkAssignModal').style.display = 'none';
}

function confirmBulkReassignment() {
  closeBulkAssignModal();

  // show spinner
  const spinner = document.createElement('div');
  spinner.id = 'bulkAssignSpinner';
  spinner.style.cssText = 'position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(255,255,255,0.7); z-index:9999; display:flex; justify-content:center; align-items:center;';
  spinner.innerHTML = `<div style="width:40px; height:40px; border:4px solid #F0EEFB; border-top:4px solid #473391; border-radius:50%; animation:spin 1s linear infinite;"></div><style>@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }</style>`;
  document.body.appendChild(spinner);

  setTimeout(() => {
    spinner.remove();
    const agent = document.getElementById('bulkAssignAgentSelect').value;
    const count = window.selectedLeadsForAssign.size;

    // update LEADS
    LEADS.forEach(l => {
       if(window.selectedLeadsForAssign.has(l.id)) {
          if(l.hlLead) l.hlLead.rm = agent;
          else l.hlLead = { rm: agent };

          const historyLog = {
             title: `System Update`,
             time: 'Just now',
             type: `Lead reassigned to ${agent} by Manager`,
             icon: '👤',
             color: '#473391',
             bg: '#F0EEFB'
          };
          l.log = l.log || [];
          l.log.unshift(historyLog);
       }
    });

    showSuccessToast(`${count} leads successfully assigned to ${agent}`);
    exitBulkAssignMode();
  }, 1000);
}

