    if (!isManager) {
        showSuccessToast('Sent to Manager for Verification');
        currentLead.log.unshift({ dot: '#F59E0B', text: `Agent Update &middot; User &middot; Payment proof submitted for manager verification &middot; Just now`, time: 'Just now' });
