        return;
    }

    let statusEl = document.querySelector('input[name="ver-status"]:checked');
    if (statusEl.value === 'Verified') {
        currentLead.bucket = 'Payment Done';
        currentLead.status = 'Payment Verified';
        currentLead.subStatus = 'Policy Issuance Pending';
