window.toggleJourneySummary = function() {
    let content = document.getElementById('journey-summary-content');
    let chevron = document.getElementById('journey-summary-chevron');
    if (content.style.display === 'none') {
        content.style.display = 'block';
        chevron.innerHTML = '▴';
    } else {
