window.advancePaymentMilestone = function(nextMilestoneIdOverride) {
    let product = window.activeNewBucketTab || 'Loan Protection';
    let insurer = window.selectedPaymentQuote ? window.selectedPaymentQuote.insurer : 'CARE Health';
    let mKey = window.getMilestoneKey(product, insurer);
    let config = MILESTONE_CONFIG[mKey];

    let currentIndex = config.milestones.findIndex(m => m.id === currentLead.paymentMilestone);
    let nextMilestone = null;

    if (nextMilestoneIdOverride) {
        nextMilestone = config.milestones.find(m => m.id === nextMilestoneIdOverride);
    } else if (currentIndex !== -1 && currentIndex < config.milestones.length - 1) {
        nextMilestone = config.milestones[currentIndex + 1];
    }

    if (nextMilestone) {
        let currentM = config.milestones[currentIndex];
        let agentName = (window.CURRENT_ROLE === 'MANAGER' || (document.getElementById('role-select') && document.getElementById('role-select').value === 'Manager')) ? 'IBM Manager' : 'IBM Agent';
        currentLead.log.unshift({ dot: 'var(--primary)', text: `Agent Update &middot; ${agentName} &middot; ${currentM ? currentM.label : currentLead.paymentMilestone} marked as complete &middot; Just now`, time: 'Just now' });

        currentLead.paymentMilestone = nextMilestone.id;
        currentLead.subStatus = nextMilestone.label;
        renderLeadDetail();
        renderLeadTable();
        renderRightPanel();
    }
};

