    let agentName = (window.CURRENT_ROLE === 'MANAGER' || (document.getElementById('role-select') && document.getElementById('role-select').value === 'Manager')) ? 'IBM Manager' : 'IBM Agent';
    if (decision === 'Approved') {
        currentLead.log.unshift({ dot: 'var(--primary)', text: `Agent Update &middot; Policy decision: Approved &middot; Just now`, time: 'Just now' });
        window.advancePaymentMilestone('policy_copy_upload');
    } else if (decision === 'Counter Offer') {
        currentLead.paymentMilestoneState = 'counter-offer';
        renderLeadDetail();
    } else if (decision === 'Rejected') {
        document.getElementById('lost-reason').value = 'Insurer Rejected';
        window.openLostModal('Underwriting Related', 'Insurer Rejected');
    }
};

