    }

    let section1Html = `
        <div style="background: white; border: 1px solid #E5E7EB; border-radius: 10px; overflow: hidden; margin-top: 16px;">
            <div style="background: #F9FAFB; padding: 12px 16px; display: flex; justify-content: space-between; align-items: center; cursor: pointer;" onclick="toggleJourneySummary()">
                <div style="font-size: 12px; font-weight: 700; color: #111827;">Journey Summary</div>
                <div id="journey-summary-chevron" style="color: #9CA3AF; font-size: 16px;">▾</div>
            </div>
