                    ${quoteSharedHtml}
                </div>
                <div style="height: 1px; background: #F3F4F6; margin: 12px 0;"></div>
                <div>
                    <div style="font-size: 9px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 8px;">PAYMENT</div>
