window.openPolicyBazaarFlow = function() {
    if (!window.newBucketValid) {
        const form = document.getElementById('new-bucket-form');
        const requiredInputs = form.querySelectorAll('input:not([disabled]).new-bucket-input, select:not([disabled]).new-bucket-input');
        let isValid = true;
        requiredInputs.forEach(inp => {
            if(inp.type === 'radio' || inp.type === 'checkbox') return;
            if (inp.value.trim() === '') {
                inp.classList.add('error');
                let err = inp.parentElement.querySelector('.inline-error-msg');
                if (err) err.style.display = 'block';
                isValid = false;
            } else {
                inp.classList.remove('error');
                let err = inp.parentElement.querySelector('.inline-error-msg');
                if (err) err.style.display = 'none';
            }
        });
        if (!isValid) return;
    }

    if (currentLead.bucket === 'New') {
        currentLead.bucket = 'Contacted';
        renderLeadTable();
    }

    window.pbQuoteFlowState = 'opened';
    let agentName = (window.CURRENT_ROLE === 'MANAGER' || (document.getElementById('role-select') && document.getElementById('role-select').value === 'Manager')) ? 'IBM Manager' : 'IBM Agent';
    currentLead.log.unshift({ dot: 'var(--primary)', text: `Agent Update &middot; ${agentName} &middot; PolicyBazaar opened in new tab &middot; Product: ${window.activeNewBucketTab}`, time: 'Just now' });

    window.open('https://www.policybazaar.com', '_blank');
    renderLeadDetail();
};

