function renderPolicyIssuedStage() {
    let product = window.activeNewBucketTab || 'Loan Protection';
    let insurer = window.selectedPaymentQuote ? window.selectedPaymentQuote.insurer : 'CARE Health';
    let mKey = window.getMilestoneKey(product, insurer);
    let fDays = FREELOOK_DAYS[mKey] || 15;

    let pStartDateStr = document.getElementById('pol-sd') ? document.getElementById('pol-sd').value : '2026-06-29';
    let pStart = new Date(pStartDateStr);
    let fEnd = new Date(pStart.getTime() + fDays * 24 * 60 * 60 * 1000);
    let fEndStr = fEnd.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' }).replace(/ /g, ' ');

    let today = new Date();
    let fBadge = '';
    if (today <= fEnd) {
        fBadge = '<span style="background: #FFF8E1; color: #856404; font-size: 10px; font-weight: 700; border-radius: 4px; padding: 1px 6px; margin-left: 8px;">Freelook Active</span>';
    } else {
        fBadge = '<span style="background: #E6F4ED; color: #1A7A4A; font-size: 10px; font-weight: 700; border-radius: 4px; padding: 1px 6px; margin-left: 8px;">Freelook Completed</span>';
    }

    let pNo = document.getElementById('pol-no') ? document.getElementById('pol-no').value : 'POL/2026/89123';
    let pIns = document.getElementById('pol-ins') ? document.getElementById('pol-ins').value : insurer;
    let pSi = document.getElementById('pol-si') ? document.getElementById('pol-si').value : '5000000';
    let pPa = document.getElementById('pol-pa') ? document.getElementById('pol-pa').value : '12450';
    let pComm = (parseFloat(pPa) * 0.20).toFixed(0);

    if (!window.policyIssuedData) {
        window.policyIssuedData = {
            freelookStatus: 'Pending',
            misStatus: 'Pending',
            payoutStatus: 'Pending',
            payinStatus: 'Pending',
            misFile: null
        };
    }
    let pd = window.policyIssuedData;

    let section1 = `
        <div style="background: white; border: 1px solid #E5E7EB; border-radius: 12px; padding: 20px;">
            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;">
                <div style="font-size: 14px; font-weight: 700; color: #111827;">Policy Summary</div>
                <div style="background: #E6F4ED; color: #1A7A4A; font-size: 11px; font-weight: 700; border-radius: 20px; padding: 4px 12px;">Policy Issued</div>
            </div>
            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 16px;">
                <div>
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Policy Number</div>
                    <div style="font-size: 13px; font-weight: 600; color: #111827;">${pNo}</div>
                </div>
                <div>
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Insurer Name</div>
                    <div style="font-size: 13px; font-weight: 600; color: #111827;">${pIns}</div>
                </div>
                <div>
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Policy Start Date</div>
                    <div style="font-size: 13px; font-weight: 600; color: #111827;">${pStart.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}</div>
                </div>
                <div>
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Sum Insured</div>
                    <div style="font-size: 13px; font-weight: 600; color: #111827;">₹${parseInt(pSi).toLocaleString('en-IN')}</div>
                </div>
                <div>
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Premium Amount</div>
                    <div style="font-size: 13px; font-weight: 600; color: #111827;">₹${parseInt(pPa).toLocaleString('en-IN')}</div>
                </div>
                <div>
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Freelook Expiry Date</div>
                    <div style="font-size: 13px; font-weight: 600; color: #111827; display: flex; align-items: center;">${fEndStr} ${fBadge}</div>
                </div>
                <div style="grid-column: 1 / -1; border-top: 1px solid #F3F4F6; padding-top: 16px; margin-top: 4px;">
                    <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: #9CA3AF; margin-bottom: 2px;">Commission Expected</div>
                    <div style="font-size: 13px; font-weight: 600; color: #1A7A4A;">₹${parseInt(pComm).toLocaleString('en-IN')}</div>
                </div>
            </div>
        </div>
    `;

    const renderPill = (label, status, activeColors, type) => {
        let isSelected = pd[type] === label;
        let bg = isSelected ? activeColors.bg : 'white';
        let border = isSelected ? \`1.5px solid \${activeColors.border}\` : '1.5px solid #E5E7EB';
        let color = isSelected ? activeColors.color : '#6B7280';
        return \`<div style="border-radius: 20px; padding: 8px 20px; font-size: 12px; font-weight: 700; border: \${border}; background: \${bg}; color: \${color}; cursor: pointer; text-align: center;" onclick="setPolicyIssuedData('\${type}', '\${label}')">\${label}</div>\`;
    };

    const renderMiniPill = (label, status, activeColors, type) => {
        let isSelected = pd[type] === label;
        let bg = isSelected ? activeColors.bg : 'white';
        let border = isSelected ? \`1.5px solid \${activeColors.border}\` : '1.5px solid #E5E7EB';
        let color = isSelected ? activeColors.color : '#6B7280';
        return \`<div style="border-radius: 20px; padding: 6px 18px; font-size: 12px; font-weight: 600; border: \${border}; background: \${bg}; color: \${color}; cursor: pointer; text-align: center;" onclick="setPolicyIssuedData('\${type}', '\${label}')">\${label}</div>\`;
    };

    let fStatusPill = '';
    if (pd.freelookStatus === 'Pending') fStatusPill = \`<div style="border-radius: 20px; padding: 4px 12px; font-size: 11px; font-weight: 700; border: 1.5px solid #F5CBA7; background: #FFF8E1; color: #856404;">Pending</div>\`;
    if (pd.freelookStatus === 'Completed') fStatusPill = \`<div style="border-radius: 20px; padding: 4px 12px; font-size: 11px; font-weight: 700; border: 1.5px solid #A8D5B5; background: #E6F4ED; color: #1A7A4A;">Completed</div>\`;
