function openLostModal() {
  if(!currentLead) return;

  const summary = document.getElementById('lostModalLeadSummary');
  const prod = currentLead.finalProduct || currentLead.initialProduct || '';
  summary.innerHTML = `${currentLead.id} &middot; ${currentLead.name} &middot; ${getProductLabel(prod)} &middot; ${currentLead.bucket}`;

  const reasonSelect = document.getElementById('lostModalReason');
  reasonSelect.innerHTML = '<option value="" disabled selected style="color: #9CA3AF;">Select a reason</option>';

  let reasons = [];
  if (currentLead.bucket === 'New' || currentLead.bucket === 'Contacted') {
     reasons = ['Not Interested', 'Already Insured', 'Wrong Number / Unreachable', 'Duplicate Lead', 'Other'];
  } else if (currentLead.bucket === 'Quote') {
     reasons = ['Premium Too High', 'Competitor Chosen', 'No Response After Quote', 'Payment Abandoned', 'Other'];
  } else if (currentLead.bucket === 'Payment Done') {
     reasons = ['Payment Not Received', 'Payment Failed', 'Counter Offer Rejected', 'Medical Rejected', 'Insurer Rejected', 'Other'];
  } else if (currentLead.bucket === 'Policy Issued') {
     reasons = ['Free Look Cancellation', 'Customer Cancellation', 'Other'];
  }

  reasons.forEach(r => {
     reasonSelect.innerHTML += `<option value="${r}">${r}</option>`;
  });

  document.getElementById('lostModalNotes').value = '';
  updateLostConfirmButton();

  const overlay = document.getElementById('lostModalOverlay');
  overlay.style.display = 'flex';
}

function closeLostModal() {
  const overlay = document.getElementById('lostModalOverlay');
  overlay.style.display = 'none';
}

function updateLostConfirmButton() {
  const reason = document.getElementById('lostModalReason').value;
  const btn = document.getElementById('lostModalConfirmBtn');
  if (reason) {
     btn.disabled = false;
     btn.style.opacity = '1';
  } else {
     btn.disabled = true;
     btn.style.opacity = '0.4';
  }
}

function confirmMarkAsLost() {
  const reason = document.getElementById('lostModalReason').value;
  const notes = document.getElementById('lostModalNotes').value;

  if (!reason) return;

  currentLead.previousBucket = currentLead.bucket;
  currentLead.bucket = 'Lost';
  currentLead.isLost = true;
  currentLead.lostReason = reason;
  currentLead.lostNotes = notes;

  const logEntry = {
    title: 'Agent Update',
    time: 'Just now',
    type: `Lead marked as Lost &middot; Stage: ${currentLead.previousBucket} &middot; Reason: ${reason} ${notes ? '&middot; ' + notes : ''}`,
    icon: '📝',
    color: '#C0392B',
    bg: '#FEF2F2'
  };
  currentLead.log = currentLead.log || [];
  currentLead.log.unshift(logEntry);

  closeLostModal();
  renderLeadTable();
  renderLeadDetail();
}

function checkReopenEnable() {
    const input = document.getElementById('reopenReasonInput').value;
    const btn = document.getElementById('confirmReopenBtn');
    if (input && input.length >= 5) {
        btn.disabled = false;
        btn.style.opacity = '1';
    } else {
        btn.disabled = true;
        btn.style.opacity = '0.4';
    }
}

function confirmReopen() {
  const reason = document.getElementById('reopenReasonInput').value;
  if (!reason || reason.length < 5) return;

  currentLead.isLost = false;
  currentLead.bucket = currentLead.previousBucket || 'New';

  const logEntry = {
    title: 'IBM Manager',
    time: 'Just now',
    type: `Lead reopened from Lost &middot; Reason: ${reason}`,
    icon: '🔄',
    color: '#473391',
    bg: '#F0EEFB'
  };
  currentLead.log.unshift(logEntry);

  showSuccessToast(`Lead reopened. Returned to ${currentLead.bucket} stage.`);
  renderLeadTable();
  renderLeadDetail();
}

args.TargetContent:
function openLostModal() {
  if(!currentLead) return;
  document.getElementById('lostModalOverlay').classList.add('open');
  document.getElementById('lostModal').style.display = 'block';
  document.getElementById('lostCategorySelect').value = '';
  document.getElementById('lostReasonSelect').value = '';
  document.getElementById('lostReasonSelect').disabled = true;
  document.getElementById('lostRemarksInput').value = '';
  document.getElementById('allowReopenCheckbox').checked = true;
}

function closeLostModal() {
  document.getElementById('lostModalOverlay').classList.remove('open');
  document.getElementById('lostModal').style.display = 'none';
}

const LOST_REASONS_MAP = {
  'Customer Related': ['Not Interested', 'Already Insured', 'Wrong Number', 'Duplicate Lead', 'Language Barrier'],
  'Quote Related': ['Premium Too High', 'Competitor Chosen', 'No Response'],
  'Payment Related': ['Payment Not Received', 'Payment Failed'],
  'Underwriting Related': ['Medical Rejected', 'Counter Offer Rejected', 'Insurer Rejected']
};

function updateLostReasons() {
  const cat = document.getElementById('lostCategorySelect').value;
  const reasonSelect = document.getElementById('lostReasonSelect');
  reasonSelect.innerHTML = '<option value="">Select Reason</option>';
  if (cat && LOST_REASONS_MAP[cat]) {
    LOST_REASONS_MAP[cat].forEach(r => {
      reasonSelect.innerHTML += `<option value="${r}">${r}</option>`;
    });
    reasonSelect.disabled = false;
  } else {
    reasonSelect.disabled = true;
  }
}

function saveLostState() {
  const cat = document.getElementById('lostCategorySelect').value;
  const reason = document.getElementById('lostReasonSelect').value;
  const remarks = document.getElementById('lostRemarksInput').value;
  const allowReopen = document.getElementById('allowReopenCheckbox').checked;

  if (!cat || !reason || !remarks.trim()) {
    showToast('Category, Reason, and Remarks are mandatory.');
    return;
  }

  currentLead.lastActiveBucket = currentLead.bucket;
  currentLead.bucket = 'Lost';
  currentLead.isLost = true;
  currentLead.lostMetadata = {
    category: cat,
    reason: reason,
    remarks: remarks,
    allowReopen: allowReopen,
    timestamp: new Date().toLocaleString(),
    agent: 'Verification Agent'
  };

  currentLead.log.unshift({
    dot: '#EF4444',
    text: `Marked as Lost: ${reason} (${cat})<br>Remarks: ${remarks}`,
    time: 'Just now'
  });

  closeLostModal();
  renderLeadTable();
  renderLeadDetail();
  showToast('Lead marked as lost');
}

function reopenLead() {
  if(!currentLead || !currentLead.isLost) return;
  currentLead.isLost = false;
  currentLead.bucket = currentLead.lastActiveBucket || 'New';

  currentLead.log.unshift({
    dot: '#10B981',
    text: 'Lead Reopened',
    time: 'Just now'
  });

  renderLeadTable();
  renderLeadDetail();
  showToast('Lead reopened successfully');
}

