  let row1Ids = ['filter-product','filter-source','filter-status','filter-agent','filter-followup','filter-created','filter-insurer','filter-search'];
  let row2Ids = ['filter-hlstage','filter-bank','filter-loanamount','filter-premium','filter-pendingwith','filter-paymentstatus','filter-leadage','filter-statusupdated'];

  let hasRow1Filter = false;
  row1Ids.forEach(id => {
