function getFilteredLeads() {
  let leads = LEADS.filter(l => !(l.isLost && window.CURRENT_ROLE !== 'MANAGER'));

  // Stage filter
  if (window.listingActiveStage && window.listingActiveStage !== 'All') {
    leads = leads.filter(l => l.bucket === window.listingActiveStage);
  }

  let getVal = (id) => { let el = document.getElementById(id); return el ? el.value : ''; };

  // ROW 1 Filters
  let prodF = getVal('filter-product');
  if (prodF) leads = leads.filter(l => getProductLabel(l.finalProduct || l.initialProduct) === prodF);

  let srcF = getVal('filter-source');
  if (srcF) leads = leads.filter(l => (l.source || 'Manual').toLowerCase() === srcF.toLowerCase());

  let statF = getVal('filter-status');
  if (statF) leads = leads.filter(l => l.status === statF);

  let agtF = getVal('filter-agent');
  if (agtF) leads = leads.filter(l => (l.hlLead && l.hlLead.rm) === agtF || l.agent === agtF);

  let fupF = getVal('filter-followup');
  if (fupF) {
    leads = leads.filter(l => {
      let fup = (l.followUpDate || '').toLowerCase();
      if (fupF === 'Overdue') return fup.includes('overdue');
      if (fupF === 'Due Today') return fup.includes('today') && !fup.includes('overdue');
      if (fupF === 'Due This Week') return fup.includes('week') || fup.includes('today') || fup.includes('tomorrow');
      if (fupF === 'No Follow-up') return !l.followUpDate || l.followUpDate === 'No Follow-up';
      return true;
    });
  }

  let timeF = getVal('filter-created');
  if (timeF) {
    let now = Date.now();
    leads = leads.filter(l => {
      if (!l.createdAt) return false;
      let dt = new Date(l.createdAt).getTime();
      let diffDays = (now - dt) / 86400000;
      if (timeF === 'Today') return diffDays <= 1;
      if (timeF === 'This Week') return diffDays <= 7;
      if (timeF === 'This Month') return diffDays <= 30;
      return true;
    });
  }

  let insF = getVal('filter-insurer');
  if (insF) leads = leads.filter(l => (l.finalInsurer || (l.selectedPlan && l.selectedPlan.insurer) || '') === insF);

  // ROW 2 Filters
  let hlF = getVal('filter-hlstage');
  if (hlF) leads = leads.filter(l => (l.hlLead && l.hlLead.hlStage) === hlF);

  let bnkF = getVal('filter-bank');
  if (bnkF) leads = leads.filter(l => (l.hlLead ? l.hlLead.bank : l.loanBank) === bnkF);

  let lnAmt = getVal('filter-loanamount');
  if (lnAmt) {
    leads = leads.filter(l => {
      let amt = parseInt(l.si) || 0;
      if (lnAmt === 'Below ₹25L') return amt < 2500000;
      if (lnAmt === '₹25L–₹50L') return amt >= 2500000 && amt < 5000000;
      if (lnAmt === '₹50L–₹1Cr') return amt >= 5000000 && amt <= 10000000;
      if (lnAmt === '₹1Cr+') return amt > 10000000;
      return true;
    });
  }

  let prmF = getVal('filter-premium');
  if (prmF) {
    leads = leads.filter(l => {
      let prmStr = (l.selectedPlan && l.selectedPlan.premium) || '';
      if (!prmStr && l.bucketData && l.bucketData['Loan Protection']) {
          // try to extract premium from LP if any
          prmStr = '12500'; // mock fallback
      }
      let prm = parseInt(prmStr.replace(/,/g, '')) || 0;
      if (!prm) return false;
      if (prmF === 'Below ₹10K') return prm < 10000;
      if (prmF === '₹10K–₹50K') return prm >= 10000 && prm <= 50000;
      if (prmF === '₹50K–₹2L') return prm > 50000 && prm <= 200000;
      if (prmF === '₹2L+') return prm > 200000;
      return true;
    });
  }

  let pendF = getVal('filter-pendingwith');
  if (pendF) leads = leads.filter(l => l.pendingWith === pendF);

  let payStF = getVal('filter-paymentstatus');
  if (payStF && (window.listingActiveStage === 'Payment Done' || window.listingActiveStage === 'Quote' || window.listingActiveStage === 'All')) {
    leads = leads.filter(l => l.subStatus === payStF || (l.paymentStatus && l.paymentStatus === payStF));
  }

  let ageF = getVal('filter-leadage');
  if (ageF) {
    let now = Date.now();
    leads = leads.filter(l => {
      if (!l.createdAt) return false;
      let days = (now - new Date(l.createdAt).getTime()) / 86400000;
      if (ageF === 'Less than 7 days') return days < 7;
      if (ageF === '7–30 days') return days >= 7 && days <= 30;
      if (ageF === '30–60 days') return days > 30 && days <= 60;
      if (ageF === '60+ days') return days > 60;
      return true;
    });
  }

  let updF = getVal('filter-statusupdated');
  if (updF) {
    let now = Date.now();
    leads = leads.filter(l => {
      let ts = l.statusUpdatedAt || l.createdAt;
      if (!ts) return false;
      let days = (now - new Date(ts).getTime()) / 86400000;
      if (updF === 'Today') return days <= 1;
      if (updF === 'Yesterday') return days > 1 && days <= 2;
      if (updF === 'This Week') return days <= 7;
      if (updF === 'This Month') return days <= 30;
      return true;
    });
  }

  // Search filter
  let q = getVal('filter-search').toLowerCase();
  if (q) {
    leads = leads.filter(l => 
      l.name.toLowerCase().includes(q) || 
      l.phone.toLowerCase().includes(q) || 
      l.id.toLowerCase().includes(q)
    );
  }

  // Sort
  let sv = getVal('filter-sort') || 'newest';

  let getAmt = (l) => parseInt(l.si) || 0;
  let getPrem = (l) => {
      let str = (l.selectedPlan && l.selectedPlan.premium) ? l.selectedPlan.premium.replace(/,/g,'') : '0';
      return parseInt(str) || 0;
  };

  leads.sort((a, b) => {
    if (sv === 'oldest' || sv === 'age-oldest') return new Date(a.createdAt) - new Date(b.createdAt);
    if (sv === 'status-updated') {
        let tA = new Date(a.statusUpdatedAt || a.createdAt);
        let tB = new Date(b.statusUpdatedAt || b.createdAt);
        return tB - tA;
    }
    if (sv === 'followup-earliest') {
        let fA = a.followUpDate ? 1 : 0;
        let fB = b.followUpDate ? 1 : 0;
        return fB - fA; // naive sort for now
    }
    if (sv === 'followup-overdue') {
        let isOverA = (a.followUpDate||'').toLowerCase().includes('overdue') ? 1 : 0;
        let isOverB = (b.followUpDate||'').toLowerCase().includes('overdue') ? 1 : 0;
        if (isOverA !== isOverB) return isOverB - isOverA;
    }
    if (sv === 'premium-desc') return getPrem(b) - getPrem(a);
    if (sv === 'premium-asc') return getPrem(a) - getPrem(b);
    if (sv === 'loan-desc') return getAmt(b) - getAmt(a);
    if (sv === 'loan-asc') return getAmt(a) - getAmt(b);

    // Default 'newest'
    return new Date(b.createdAt) - new Date(a.createdAt);
  });

  return leads;
}

window.setListingStage = function(stage) {
  window.listingActiveStage = stage;

  // Interaction rule for Payment Status
  let payF = document.getElementById('filter-paymentstatus');
  if (payF) {
      if (stage === 'New' || stage === 'Contacted') {
          payF.disabled = true;
          payF.title = "Not applicable for this stage";
          payF.value = "";
      } else {
          payF.disabled = false;
          payF.title = "";
      }
  }

  renderStageTabs();
  applyListingFilters(); // Re-apply and re-render
};

