function getFilteredLeads() {
  let leads = LEADS.filter(l => !(l.isLost && window.CURRENT_ROLE !== 'MANAGER'));

  // Stage filter
  if (window.listingActiveStage && window.listingActiveStage !== 'All') {
    leads = leads.filter(l => l.bucket === window.listingActiveStage);
  }

  // Product filter
  let prodFilter = document.getElementById('filter-product');
  if (prodFilter && prodFilter.value) {
    leads = leads.filter(l => {
      let prod = getProductLabel(l.finalProduct || l.initialProduct);
      return prod === prodFilter.value;
    });
  }

  // Source filter
  let srcFilter = document.getElementById('filter-source');
  if (srcFilter && srcFilter.value) {
    leads = leads.filter(l => (l.source || 'Manual').toLowerCase() === srcFilter.value.toLowerCase());
  }

  // Status filter
  let statusFilter = document.getElementById('filter-status');
  if (statusFilter && statusFilter.value) {
    leads = leads.filter(l => l.status === statusFilter.value);
  }

  // Follow-up filter
  let fupFilter = document.getElementById('filter-followup');
  if (fupFilter && fupFilter.value) {
    let fv = fupFilter.value;
    leads = leads.filter(l => {
      let fup = (l.followUpDate || '').toLowerCase();
      if (fv === 'Overdue') return fup.includes('overdue');
      if (fv === 'Due Today') return fup.includes('today') && !fup.includes('overdue');
      if (fv === 'Due This Week') return fup.includes('week') || fup.includes('today') || fup.includes('tomorrow');
      if (fv === 'No Follow-up') return !l.followUpDate || l.followUpDate === 'No Follow-up';
      return true;
    });
  }

  // Search filter
  let searchInput = document.getElementById('filter-search');
  if (searchInput && searchInput.value.trim()) {
    let q = searchInput.value.trim().toLowerCase();
    leads = leads.filter(l => 
      l.name.toLowerCase().includes(q) || 
      l.phone.toLowerCase().includes(q) || 
      l.id.toLowerCase().includes(q)
    );
  }

  // Sort
  let sortVal = document.getElementById('filter-sort');
  let sv = sortVal ? sortVal.value : 'newest';
  if (sv === 'oldest') leads.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
  else if (sv === 'newest') leads.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

  return leads;
}

window.setListingStage = function(stage) {
  window.listingActiveStage = stage;
  renderStageTabs();
  renderLeadTable();
};

