js_marker = 'function renderManagerDashboard() {'
js_logic = """
    window.globalMISData = [];
    window.misActiveTab = 'uploads';

    function renderMISPage() {
        let content = document.getElementById('mis-content');
        if (!content) return;

        let headerHtml = `
            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px;">
                <div>
                    <div style="font-size: 20px; font-weight: 700; color: #111827; margin-bottom: 4px;">MIS & Payouts</div>
                    <div style="font-size: 13px; color: #6B7280;">Upload insurer MIS, track commissions, confirm freelook completions, manage payouts.</div>
                </div>
                <button style="background: #473391; color: white; border: none; border-radius: 8px; font-size: 13px; font-weight: 700; padding: 10px 20px; cursor: pointer;" onclick="document.getElementById('mis-upload-input').click()">+ Upload MIS</button>
                <input type="file" id="mis-upload-input" accept=".pdf,.xls,.xlsx,.csv" style="display: none;" onchange="processGlobalMIS(this)">
            </div>

            <div style="display: flex; gap: 24px; border-bottom: 2px solid #E5E7EB; margin-bottom: 24px;">
                <div style="padding-bottom: 12px; font-size: 14px; font-weight: 600; cursor: pointer; border-bottom: 3px solid ${window.misActiveTab === 'uploads' ? '#473391' : 'transparent'}; color: ${window.misActiveTab === 'uploads' ? '#473391' : '#6B7280'};" onclick="window.misActiveTab='uploads'; renderMISPage()">MIS Uploads</div>
                <div style="padding-bottom: 12px; font-size: 14px; font-weight: 600; cursor: pointer; border-bottom: 3px solid ${window.misActiveTab === 'commissions' ? '#473391' : 'transparent'}; color: ${window.misActiveTab === 'commissions' ? '#473391' : '#6B7280'};" onclick="window.misActiveTab='commissions'; renderMISPage()">Commission Tracker</div>
                <div style="padding-bottom: 12px; font-size: 14px; font-weight: 600; cursor: pointer; border-bottom: 3px solid ${window.misActiveTab === 'freelook' ? '#473391' : 'transparent'}; color: ${window.misActiveTab === 'freelook' ? '#473391' : '#6B7280'};" onclick="window.misActiveTab='freelook'; renderMISPage()">Freelook Tracker</div>
                <div style="padding-bottom: 12px; font-size: 14px; font-weight: 600; cursor: pointer; border-bottom: 3px solid ${window.misActiveTab === 'discrepancies' ? '#473391' : 'transparent'}; color: ${window.misActiveTab === 'discrepancies' ? '#473391' : '#6B7280'};" onclick="window.misActiveTab='discrepancies'; renderMISPage()">Payout Discrepancies</div>
            </div>
        `;

        let tabHtml = '';
        if (window.misActiveTab === 'uploads') {
            tabHtml = renderMISUploadsTab();
        } else if (window.misActiveTab === 'commissions') {
            tabHtml = renderCommissionTrackerTab();
        } else if (window.misActiveTab === 'freelook') {
            tabHtml = renderFreelookTrackerTab();
        } else if (window.misActiveTab === 'discrepancies') {
            tabHtml = renderPayoutDiscrepanciesTab();
        }

        content.innerHTML = headerHtml + tabHtml;
    }

    window.processGlobalMIS = function(input) {
        if (input.files && input.files[0]) {
            let file = input.files[0];
            showSuccessToast('MIS file processing...');
            setTimeout(() => {
                window.globalMISData.push({
                    date: new Date().toLocaleDateString('en-GB'),
                    insurer: 'CARE Health',
                    month: 'June 2026',
                    file: file.name,
                    policies: 24,
                    matched: 22,
                    unmatched: 2,
                    status: 'Processed'
                });

                // Simulate updating leads to verification state
                LEADS.forEach(l => {
                    if (l.bucket === 'Policy Issued' && l.freelookState === 'under_verification') {
                        // In reality, this would match based on policy number
                        l.misUploaded = true;
                    }
                });

                showSuccessToast('MIS processed successfully!');
                renderMISPage();
            }, 1000);
        }
    };

    function renderMISUploadsTab() {
        let rows = window.globalMISData.map(m => `
            <tr style="border-bottom: 1px solid #E5E7EB;">
                <td style="padding: 12px 16px; font-size: 13px; color: #4B5563;">${m.date}</td>
                <td style="padding: 12px 16px; font-size: 13px; color: #111827; font-weight: 500;">${m.insurer}</td>
                <td style="padding: 12px 16px; font-size: 13px; color: #4B5563;">${m.month}</td>
                <td style="padding: 12px 16px; font-size: 13px; color: #473391; font-weight: 600;">${m.file}</td>
                <td style="padding: 12px 16px; font-size: 13px; color: #4B5563;">${m.policies}</td>
                <td style="padding: 12px 16px; font-size: 13px; color: #10B981; font-weight: 600;">${m.matched}</td>
                <td style="padding: 12px 16px; font-size: 13px; color: #EF4444; font-weight: 600;">${m.unmatched}</td>
                <td style="padding: 12px 16px;">
                    <div style="background: #E6F4ED; color: #1A7A4A; font-size: 11px; font-weight: 700; border-radius: 20px; padding: 4px 10px; display: inline-block;">${m.status}</div>
