        `).join('');

        if (rows.length === 0) {
            rows = `<tr><td colspan="9" style="padding: 40px; text-align: center; color: #6B7280; font-size: 14px;">No MIS files uploaded yet.</td></tr>`;
        }

        return `
            <div style="background: white; border-radius: 12px; border: 1px solid #E5E7EB; overflow: hidden;">
                <div style="padding: 16px 24px; border-bottom: 1px solid #E5E7EB; background: #F9FAFB; display: flex; align-items: center; justify-content: space-between;">
                    <div style="font-size: 14px; font-weight: 700; color: #111827;">MIS History</div>
