    function renderCommissionTrackerTab() {
        let policyLeads = LEADS.filter(l => l.bucket === 'Policy Issued');

        let totalComm = 0;
        let received = 0;
        let pending = 0;

        let rows = policyLeads.map(l => {
            let prem = 12450; // Mock premium
            let comm = (prem * 0.20).toFixed(0);
            totalComm += parseFloat(comm);

            let payout = (l.policyIssuedData && l.policyIssuedData.payoutStatus) || 'Pending';
            let payin = (l.policyIssuedData && l.policyIssuedData.payinStatus) || 'Pending';

            if (payout === 'Received') received += parseFloat(comm);
            else pending += parseFloat(comm);

            let payoutPill = payout === 'Received' 
                ? \`<div style="background: #E6F4ED; color: #1A7A4A; font-size: 11px; font-weight: 700; border-radius: 20px; padding: 4px 10px; cursor: pointer; text-align: center; border: 1px solid #A8D5B5;" onclick="toggleCommissionStatus('\${l.id}', 'payoutStatus')">Received</div>\`
                : \`<div style="background: #FFF8E1; color: #856404; font-size: 11px; font-weight: 700; border-radius: 20px; padding: 4px 10px; cursor: pointer; text-align: center; border: 1px solid #F5CBA7;" onclick="toggleCommissionStatus('\${l.id}', 'payoutStatus')">Pending</div>\`;

            let payinPill = payin === 'Received' 
                ? \`<div style="background: #E6F4ED; color: #1A7A4A; font-size: 11px; font-weight: 700; border-radius: 20px; padding: 4px 10px; cursor: pointer; text-align: center; border: 1px solid #A8D5B5;" onclick="toggleCommissionStatus('\${l.id}', 'payinStatus')">Received</div>\`
                : \`<div style="background: #FFF8E1; color: #856404; font-size: 11px; font-weight: 700; border-radius: 20px; padding: 4px 10px; cursor: pointer; text-align: center; border: 1px solid #F5CBA7;" onclick="toggleCommissionStatus('\${l.id}', 'payinStatus')">Pending</div>\`;

            return \`
                <tr style="border-bottom: 1px solid #E5E7EB;">
                    <td style="padding: 12px 16px; font-size: 13px; color: #111827; font-weight: 500;">\${l.id}</td>
                    <td style="padding: 12px 16px; font-size: 13px; color: #4B5563;">\${l.name}</td>
                    <td style="padding: 12px 16px; font-size: 13px; color: #4B5563;">Health</td>
