    html = html.replace(screen_marker, '<div class="screen" id="screen-mis" style="overflow-y:auto; background:#F5F4F9; padding: 24px;">\n      <div id="mis-content" style="max-width: 1200px; margin: 0 auto;"></div>\n    </div>\n    ' + screen_marker)

# Insert renderMISPage logic
js_logic = """
    window.globalMISData = [];
