import sys
import re

def replace_function(content, func_name, new_code):
    # Find the start of the function definition
    match = re.search(r'function\s+' + func_name + r'\s*\([^)]*\)\s*\{', content)
    if not match:
        print(f"Could not find function {func_name}")
        return content

    start_idx = match.start()
    # Find the matching closing brace
    brace_count = 0
    idx = match.end() - 1 # points to the opening '{'

    while idx < len(content):
        if content[idx] == '{':
            brace_count += 1
        elif content[idx] == '}':
            brace_count -= 1
            if brace_count == 0:
                end_idx = idx + 1
                break
        idx += 1
    else:
        print(f"Could not find closing brace for {func_name}")
        return content

    # Replace the chunk
    return content[:start_idx] + new_code + content[end_idx:]

