            brace_count -= 1
        if in_function and brace_count == 0:
            end_idx = i + 1
            break

    if end_idx != -1:
        # Replace
        old_block = html[start_idx:end_idx]
        html = html[:start_idx] + new_stage_code.strip() + html[end_idx:]

