        currentLead.paymentOcrState = 0;
        renderLeadDetail();
    };

    window.sharePaymentLink = function(method) {
        currentLead.paymentLinkShared = true;
        currentLead.status = 'Payment Link Shared';
        currentLead.subStatus = 'Awaiting Payment';
