/* Chevron Stage Bar */
.chevron-stage-bar { display: flex; align-items: center; width: 100%; background: white; border-bottom: 1px solid #E5E7EB; padding: 12px 20px; box-sizing: border-box; }
.chevron-stages { display: flex; align-items: center; gap: 0; }
.stage-item { position: relative; padding: 8px 28px 8px 20px; font-size: 12px; font-weight: 500; white-space: nowrap; clip-path: polygon(0 0, calc(100% - 12px) 0, 100% 50%, calc(100% - 12px) 100%, 0 100%, 12px 50%); margin-right: -12px; min-width: 120px; text-align: center; background: #F3F4F6; color: #9CA3AF; transition: background 0.2s, color 0.2s; cursor: default; user-select: none; }
.stage-item:first-child { clip-path: polygon(0 0, calc(100% - 12px) 0, 100% 50%, calc(100% - 12px) 100%, 0 100%); padding-left: 16px; }
.stage-item.stage-done { background: #EEE8FD; color: #473391; font-weight: 600; }
.stage-item.stage-active { background: #6B5CC4; color: white; font-weight: 700; }
.stage-item:nth-child(1) { z-index: 5; }
.stage-item:nth-child(2) { z-index: 4; }
.stage-item:nth-child(3) { z-index: 3; }
.stage-item:nth-child(4) { z-index: 2; }
.stage-item:nth-child(5) { z-index: 1; }
/* keep old classes harmless for any residual references */
.sangam-tracker-box { margin-bottom: 0; padding: 0; }
.tracker-row { display: none; }

