function renderStageBar() {
  const displayBuckets = BUCKETS.filter(b => b !== 'Lost');
  const idx = BUCKETS.indexOf(currentLead.bucket);
  const isLost = currentLead.bucket === 'Lost';

  // Build chevron stages
  let stagesHtml = '';
  displayBuckets.forEach((st, i) => {
    const origIdx = BUCKETS.indexOf(st);
    const isDone = !isLost && origIdx < idx;
    const isCurrent = !isLost && origIdx === idx;
    let cls = 'stage-item';
    if (isDone)    cls += ' stage-done';
    if (isCurrent) cls += ' stage-active';
    stagesHtml += `<div class="${cls}">${st}</div>`;
  });

  // Mark as Lost button (right side, only if not already lost)
  const lostBtn = !isLost
    ? `<button style="margin-left:auto; border:1.5px solid #C0392B; color:#C0392B; background:white; border-radius:6px; padding:7px 16px; font-size:12px; font-weight:600; cursor:pointer; white-space:nowrap; flex-shrink:0;" onclick="openLostModal()">Mark as Lost</button>`
    : '';

  let html = `
    <div class="chevron-stage-bar" style="margin-bottom:24px; border-radius:12px 12px 0 0; border:1px solid #E5E7EB; border-bottom:1px solid #E5E7EB;">
      <div class="chevron-stages">${stagesHtml}</div>
      ${lostBtn}
    </div>
  `;

  if (isLost && currentLead.lostMetadata) {
    let lm = currentLead.lostMetadata;
    html += `
      <div style="background:#FEF2F2; border:1px solid #FCA5A5; border-radius:8px; padding:16px; margin-bottom:24px; display:flex; justify-content:space-between; align-items:flex-start;">
        <div>
          <div style="color:#991B1B; font-weight:700; font-size:16px; margin-bottom:8px;">Lead Marked as Lost</div>
          <div style="font-size:13px; color:#7F1D1D; margin-bottom:4px;"><strong>Reason:</strong> ${lm.reason} (${lm.category})</div>
          <div style="font-size:13px; color:#7F1D1D; margin-bottom:4px;"><strong>Remarks:</strong> ${lm.remarks}</div>
          <div style="font-size:12px; color:#991B1B; margin-top:8px;">Marked by ${lm.agent} on ${lm.timestamp}</div>
