function openLostModal() {
  if(!currentLead) return;
  document.getElementById('lostModalOverlay').style.display = 'flex';

  const summaryText = `${currentLead.id} · ${currentLead.name} · ${getProductLabel(currentLead.finalProduct || currentLead.initialProduct)} · ${currentLead.bucket}`;
  document.getElementById('lostModalLeadSummary').textContent = summaryText;

  const reasonSelect = document.getElementById('lostReasonSelect');
  reasonSelect.innerHTML = '<option value="">Select a reason</option>';

  let reasons = [];
  if (currentLead.bucket === 'New' || currentLead.bucket === 'Contacted') {
    reasons = ['Not Interested', 'Already Insured', 'Wrong Number / Unreachable', 'Duplicate Lead', 'Other'];
  } else if (currentLead.bucket === 'Quote') {
    reasons = ['Premium Too High', 'Competitor Chosen', 'No Response After Quote', 'Payment Abandoned', 'Other'];
  } else if (currentLead.bucket === 'Payment Done') {
    reasons = ['Payment Not Received', 'Payment Failed', 'Counter Offer Rejected', 'Medical Rejected', 'Insurer Rejected', 'Other'];
  } else if (currentLead.bucket === 'Policy Issued') {
    reasons = ['Free Look Cancellation', 'Customer Cancellation', 'Other'];
  } else {
    reasons = ['Other'];
  }

  reasons.forEach(r => {
    reasonSelect.innerHTML += `<option value="${r}">${r}</option>`;
  });

  document.getElementById('lostRemarksInput').value = '';
  updateLostConfirmButton();
}

function closeLostModal() {
  document.getElementById('lostModalOverlay').style.display = 'none';
}

function updateLostConfirmButton() {
  const btn = document.getElementById('lostConfirmBtn');
  if (document.getElementById('lostReasonSelect').value) {
    btn.disabled = false;
    btn.style.opacity = '1';
  } else {
    btn.disabled = true;
    btn.style.opacity = '0.4';
  }
}

function confirmMarkAsLost() {
  const reason = document.getElementById('lostReasonSelect').value;
  const remarks = document.getElementById('lostRemarksInput').value;

  closeLostModal();

  currentLead.lastActiveBucket = currentLead.bucket;
  currentLead.bucket = 'Lost';
  currentLead.isLost = true;
  currentLead.lostMetadata = {
    reason: reason,
    remarks: remarks,
    timestamp: new Date().toLocaleString(),
    agent: window.currentUserRole === 'manager' ? 'Rohit M' : 'Verification Agent'
  };

  currentLead.log.unshift({
    dot: '#C0392B',
    text: `Agent Update · ${currentLead.lostMetadata.agent} · Lead marked as Lost · Stage: ${currentLead.lastActiveBucket} · Reason: ${reason} ${remarks ? `· ${remarks}` : ''} · Just now`,
    time: 'Just now'
  });

  renderLeadDetail();
  renderLeadTable();
}

function showReopenPrompt() {
  document.getElementById('reopenPromptDiv').style.display = 'block';
}

function updateReopenBtn() {
  const val = document.getElementById('reopenReasonInput').value.trim();
  const btn = document.getElementById('confirmReopenBtn');
  if (val.length >= 5) {
    btn.disabled = false;
    btn.style.opacity = '1';
  } else {
    btn.disabled = true;
    btn.style.opacity = '0.4';
  }
}

function confirmReopen() {
  if(!currentLead || !currentLead.isLost) return;
  const reason = document.getElementById('reopenReasonInput').value.trim();

  currentLead.isLost = false;
  currentLead.bucket = currentLead.lastActiveBucket || 'New';

  currentLead.log.unshift({
    dot: '#10B981',
    text: `IBM Manager · ${window.currentUserRole === 'manager' ? 'Rohit M' : 'Verification Agent'} · Lead reopened from Lost · Reason: ${reason} · Just now`,
    time: 'Just now'
  });

  renderLeadTable();
  renderLeadDetail();
  showToast(`Lead reopened. Returned to ${currentLead.bucket} stage.`);
}

